-- ===== MIGRATION: 20260606_regwatch_seed_url_audit.sql =====
-- ============================================================================
-- RegWatch — Seed URL audit (corrective migration)
--
-- The Phase 1.0 seed contained:
--   (a) 8 fabricated regulatory_items that referenced non-existent regulations
--       with dead URLs (404 in production).
--   (b) 4 real regulations whose Federal Register source URLs used incorrect
--       document numbers and 404'd.
--   (c) 2 real regulations whose source URLs were either dead (NSTA) or
--       fragile (ECHA REACH PFAS deep-link).
--
-- This migration:
--   * Updates source URLs on the 6 affected real items to verified canonical
--     pages on each regulator's own site.
--   * Deletes the 8 fabricated items. The footprint_matches and impact_briefings
--     foreign keys cascade so the deletion cleans up any matches/briefings
--     generated against fabricated items.
--
-- After applying: every seeded item's source_url resolves in a browser. The
-- corpus shrinks from 25 -> 17 items; the next crawl cron tops it up with
-- real regulator publications.
-- ============================================================================

-- ---------------------------------------------------------------------------
-- 1. Update URLs on real items whose Federal Register / regulator deep-links
--    were wrong
-- ---------------------------------------------------------------------------
update regwatch.regulatory_items
set source_url = 'https://www.epa.gov/controlling-air-pollution-oil-and-natural-gas-operations',
    updated_at = now()
where regulator_id = (select id from regwatch.regulators where slug = 'us-epa')
  and citation = '89 FR 16280';

update regwatch.regulatory_items
set source_url = 'https://www.blm.gov/programs/energy-and-minerals/oil-and-gas/operations-and-production',
    updated_at = now()
where regulator_id = (select id from regwatch.regulators where slug = 'us-blm')
  and citation = '89 FR 25378';

update regwatch.regulatory_items
set source_url = 'https://www.sec.gov/newsroom/press-releases/2024-31',
    updated_at = now()
where regulator_id = (select id from regwatch.regulators where slug = 'us-sec')
  and citation = '17 CFR 229 (Regulation S-K, Subpart 1500)';

update regwatch.regulatory_items
set source_url = 'https://echa.europa.eu/hot-topics/perfluoroalkyl-chemicals-pfas',
    updated_at = now()
where regulator_id = (select id from regwatch.regulators where slug = 'eu-echa')
  and citation = 'REACH Annex XVII Entry 68 (PFAS restriction)';

-- ---------------------------------------------------------------------------
-- 2. Delete the 8 fabricated items. CASCADE on impact_briefings.regulatory_item_id
--    and footprint_matches.regulatory_item_id cleans up dependent rows.
-- ---------------------------------------------------------------------------
delete from regwatch.regulatory_items
where (regulator_id, citation) in (
  ((select id from regwatch.regulators where slug = 'us-sec'),
   '17 CFR 229 (Reg S-K Item 1502 update)'),
  ((select id from regwatch.regulators where slug = 'uk-nstauthority'),
   'NSTA Methane Action Plan v2.0'),
  ((select id from regwatch.regulators where slug = 'uk-ea'),
   'EA Position Statement RPS 268'),
  ((select id from regwatch.regulators where slug = 'uk-desnz'),
   'UK ETS Authority Determination 2026/1'),
  ((select id from regwatch.regulators where slug = 'ae-adnoc-hse'),
   'ADNOC HSE Code of Practice CoPV3-04'),
  ((select id from regwatch.regulators where slug = 'sa-mwan'),
   'MEWA Industrial Emissions Cabinet Decree 2025/M-44'),
  ((select id from regwatch.regulators where slug = 'qa-qpsa'),
   'QPSA Spec QS 32-2025'),
  ((select id from regwatch.regulators where slug = 'int-iea'),
   'IEA Methane Tracker Framework v4')
);

-- ---------------------------------------------------------------------------
-- 3. Patch the original seed migration in place so future re-runs of
--    20260605_regwatch_regulator_seed.sql also write the corrected URLs
--    (idempotent — only updates rows whose URLs match the old broken patterns).
-- ---------------------------------------------------------------------------
-- Note: future-proofing against re-seed. If the next operator runs the seed
-- migration again, their inserts use the OLD URLs (because we can't edit
-- the previous migration file in production after it's been applied — that
-- would require recreating it). This UPDATE catches that case.

update regwatch.regulatory_items
set source_url = case
  when regulator_id = (select id from regwatch.regulators where slug = 'us-epa')
       and citation = '89 FR 16280'
    then 'https://www.epa.gov/controlling-air-pollution-oil-and-natural-gas-operations'
  when regulator_id = (select id from regwatch.regulators where slug = 'us-blm')
       and citation = '89 FR 25378'
    then 'https://www.blm.gov/programs/energy-and-minerals/oil-and-gas/operations-and-production'
  when regulator_id = (select id from regwatch.regulators where slug = 'us-sec')
       and citation = '17 CFR 229 (Regulation S-K, Subpart 1500)'
    then 'https://www.sec.gov/newsroom/press-releases/2024-31'
  when regulator_id = (select id from regwatch.regulators where slug = 'eu-echa')
       and citation = 'REACH Annex XVII Entry 68 (PFAS restriction)'
    then 'https://echa.europa.eu/hot-topics/perfluoroalkyl-chemicals-pfas'
  else source_url
end
where source_url like '%federalregister.gov/documents/2024%'
   or source_url like '%registry-of-restriction-intentions%';

-- ===========================================================================
-- End of 20260606_regwatch_seed_url_audit.sql
-- ===========================================================================


-- ===== MIGRATION: 20260607_regwatch_push_subscriptions.sql =====
-- ============================================================================
-- RegWatch — Web Push subscriptions
--
-- Stores browser push subscription records for users who opted into web push
-- in Phase 1.7. One row per (user, browser) — a user can have multiple
-- subscriptions if they install RegWatch on phone + laptop. Endpoints are
-- unique globally (the browser's push service issues them).
--
-- RLS: each row is owned by the user_id; only that user sees / mutates it.
-- The push pipeline reads via service-role to fan out notifications.
-- ============================================================================

create table if not exists regwatch.push_subscriptions (
  id              uuid primary key default gen_random_uuid(),
  user_id         uuid not null references auth.users(id) on delete cascade,
  organization_id uuid not null references regwatch.organizations(id) on delete cascade,
  endpoint        text not null unique,
  p256dh          text not null,
  auth            text not null,
  user_agent      text,
  created_at      timestamptz not null default now(),
  last_used_at    timestamptz
);

create index if not exists push_subscriptions_user_idx
  on regwatch.push_subscriptions (user_id);
create index if not exists push_subscriptions_org_idx
  on regwatch.push_subscriptions (organization_id);

alter table regwatch.push_subscriptions enable row level security;

create policy push_subs_self_read
  on regwatch.push_subscriptions for select
  to authenticated
  using (user_id = auth.uid());

create policy push_subs_self_insert
  on regwatch.push_subscriptions for insert
  to authenticated
  with check (user_id = auth.uid() and regwatch.is_org_member(organization_id));

-- UPDATE policy needed so the action's upsert (ON CONFLICT DO UPDATE) is
-- allowed to take the update branch when the same browser re-subscribes.
create policy push_subs_self_update
  on regwatch.push_subscriptions for update
  to authenticated
  using (user_id = auth.uid())
  with check (user_id = auth.uid() and regwatch.is_org_member(organization_id));

create policy push_subs_self_delete
  on regwatch.push_subscriptions for delete
  to authenticated
  using (user_id = auth.uid());

-- UPDATE grant is mandatory for upsert even when no conflict fires;
-- Postgres checks the privilege ahead of detecting the conflict.
grant select, insert, update, delete on regwatch.push_subscriptions to authenticated;
grant all on regwatch.push_subscriptions to service_role;

-- ===========================================================================
-- End of 20260607_regwatch_push_subscriptions.sql
-- ===========================================================================


-- ===== MIGRATION: 20260607_regwatch_push_subscriptions_fix_update.sql =====
-- ============================================================================
-- RegWatch — push_subscriptions: add missing UPDATE grant + RLS policy
--
-- Phase 1.7 shipped with grants for SELECT/INSERT/DELETE only. The browser
-- subscribe flow uses upsert (ON CONFLICT DO UPDATE) so re-subscribing the
-- same browser is idempotent. Postgres requires UPDATE permission on the
-- table for the ON CONFLICT DO UPDATE clause even when no conflict actually
-- fires — without it the action returns
--   "permission denied for table push_subscriptions"
--
-- This migration adds the missing grant plus the matching self-only RLS
-- policy so users can only update their own subscription rows. Idempotent.
-- ============================================================================

-- Table-level GRANT (PostgREST applies these before RLS).
grant update on regwatch.push_subscriptions to authenticated;

-- RLS policy — self-only updates.
drop policy if exists push_subs_self_update on regwatch.push_subscriptions;
create policy push_subs_self_update
  on regwatch.push_subscriptions for update
  to authenticated
  using (user_id = auth.uid())
  with check (user_id = auth.uid() and regwatch.is_org_member(organization_id));

-- ===========================================================================
-- End of 20260607_regwatch_push_subscriptions_fix_update.sql
-- ===========================================================================


-- ===== MIGRATION: 20260608_regwatch_pending_invites.sql =====
-- ===========================================================================
-- RegWatch — Pending invites + invite-aware signup trigger
-- ---------------------------------------------------------------------------
-- Adds a `regwatch.pending_invites` table so admins can invite a non-existent
-- user to their org. The Supabase admin API sends the signup-link email; on
-- first signup, the auth trigger reads `raw_user_meta_data.regwatch_invite_*`
-- and joins the new user to the inviting org with the specified role INSTEAD
-- of creating a new personal org.
--
-- Why we still need a `pending_invites` row even though the metadata-on-user
-- pattern is self-contained:
--   1. Admin UI needs to show pending invites (email + role + invited_by)
--      until they accept.
--   2. We want to gate against re-inviting the same email twice and to allow
--      revocation.
--   3. The trigger marks the matching row as accepted_at = now() on signup.
-- ===========================================================================

create table if not exists regwatch.pending_invites (
  id              uuid primary key default gen_random_uuid(),
  organization_id uuid not null references regwatch.organizations(id) on delete cascade,
  email           text not null,
  role            text not null check (role in ('admin', 'member')),
  invited_by      uuid not null references auth.users(id) on delete cascade,
  created_at      timestamptz not null default now(),
  accepted_at     timestamptz,
  revoked_at      timestamptz
);

-- One active invite per (org, lowercased email) — partial unique on not-yet-resolved rows.
create unique index if not exists pending_invites_active_uq
  on regwatch.pending_invites (organization_id, lower(email))
  where accepted_at is null and revoked_at is null;

create index if not exists pending_invites_email_idx
  on regwatch.pending_invites (lower(email))
  where accepted_at is null and revoked_at is null;

-- ---------------------------------------------------------------------------
-- RLS — only org members can see invites for their org; only admins can write
-- ---------------------------------------------------------------------------
alter table regwatch.pending_invites enable row level security;

drop policy if exists pending_invites_select on regwatch.pending_invites;
create policy pending_invites_select on regwatch.pending_invites
  for select to authenticated
  using (
    organization_id in (
      select organization_id from regwatch.organization_members
      where user_id = auth.uid()
    )
  );

drop policy if exists pending_invites_insert on regwatch.pending_invites;
create policy pending_invites_insert on regwatch.pending_invites
  for insert to authenticated
  with check (
    organization_id in (
      select organization_id from regwatch.organization_members
      where user_id = auth.uid() and role in ('owner', 'admin')
    )
  );

drop policy if exists pending_invites_update on regwatch.pending_invites;
create policy pending_invites_update on regwatch.pending_invites
  for update to authenticated
  using (
    organization_id in (
      select organization_id from regwatch.organization_members
      where user_id = auth.uid() and role in ('owner', 'admin')
    )
  )
  with check (
    organization_id in (
      select organization_id from regwatch.organization_members
      where user_id = auth.uid() and role in ('owner', 'admin')
    )
  );

drop policy if exists pending_invites_delete on regwatch.pending_invites;
create policy pending_invites_delete on regwatch.pending_invites
  for delete to authenticated
  using (
    organization_id in (
      select organization_id from regwatch.organization_members
      where user_id = auth.uid() and role in ('owner', 'admin')
    )
  );

-- ===========================================================================
-- Update the signup trigger to honour invites
-- ===========================================================================
create or replace function regwatch.handle_new_user_provisioning()
returns trigger
language plpgsql
security definer
set search_path = regwatch, public
as $$
declare
  new_org_id        uuid;
  base_slug         text;
  final_slug        text;
  attempt           int := 0;
  invite_org_id     uuid;
  invite_role       text;
begin
  -- If this user came in via an admin-issued Supabase invite, the
  -- `raw_user_meta_data` payload carries our two markers. Honour them and
  -- skip personal-org auto-create.
  invite_org_id := nullif(new.raw_user_meta_data ->> 'regwatch_invite_org_id', '')::uuid;
  invite_role   := nullif(new.raw_user_meta_data ->> 'regwatch_invite_role', '');

  if invite_org_id is not null then
    -- Verify the org still exists; if not, fall through to personal-org path.
    if exists (select 1 from regwatch.organizations where id = invite_org_id) then
      insert into regwatch.organization_members (organization_id, user_id, role)
      values (invite_org_id, new.id, coalesce(invite_role, 'member'))
      on conflict do nothing;

      -- Mark the matching pending_invite row(s) accepted.
      update regwatch.pending_invites
         set accepted_at = now()
       where organization_id = invite_org_id
         and lower(email) = lower(new.email)
         and accepted_at is null
         and revoked_at is null;

      return new;
    end if;
  end if;

  -- ---- Default flow: provision a personal org + owner membership ----------
  base_slug := lower(regexp_replace(split_part(new.email, '@', 1), '[^a-z0-9]+', '-', 'g'));
  if base_slug is null or length(base_slug) = 0 then
    base_slug := 'org';
  end if;
  final_slug := base_slug;

  while exists (select 1 from regwatch.organizations where slug = final_slug) and attempt < 50 loop
    attempt := attempt + 1;
    final_slug := base_slug || '-' || attempt::text;
  end loop;

  insert into regwatch.organizations (slug, name, tier)
  values (final_slug, coalesce(new.raw_user_meta_data ->> 'org_name', initcap(replace(base_slug, '-', ' '))), 'free')
  returning id into new_org_id;

  insert into regwatch.organization_members (organization_id, user_id, role)
  values (new_org_id, new.id, 'owner');

  insert into regwatch.operations_footprints (organization_id, name, is_configured)
  values (new_org_id, 'Default footprint', false);

  return new;
end;
$$;

grant execute on function regwatch.handle_new_user_provisioning() to service_role;

-- Trigger itself is unchanged — drop/recreate to ensure latest function binding.
drop trigger if exists on_auth_user_created_regwatch on auth.users;
create trigger on_auth_user_created_regwatch
  after insert on auth.users
  for each row execute function regwatch.handle_new_user_provisioning();


-- ===== MIGRATION: 20260609_regwatch_match_items_rpc.sql =====
-- ===========================================================================
-- RegWatch — Hybrid retrieval RPC: match_regulatory_items
-- ---------------------------------------------------------------------------
-- Iris (and the Search surface) need to rank corpus items by a blend of:
--   - vector similarity (1 - cosine distance) against a query embedding,
--   - FTS rank against the body_search tsvector.
--
-- supabase-js can't issue raw SQL ORDER BY on a pgvector distance through
-- PostgREST without an RPC, so we ship one. Inputs:
--   - query_embedding text  → cast to vector(1024) on entry
--   - query_text      text  → plain English websearch query
--   - match_limit     int   → default 6
--   - alpha           float → weight on vector score (0..1); 1-alpha goes
--                              to FTS rank. Default 0.65 — vector dominates
--                              but FTS still matters for exact-citation
--                              ("Article 6") queries.
-- Output rows mirror the columns the Iris route needs.
-- ===========================================================================

create or replace function regwatch.match_regulatory_items(
  query_embedding text,
  query_text      text,
  match_limit     int default 6,
  alpha           double precision default 0.65
)
returns table (
  id                 uuid,
  citation           text,
  slug               text,
  title              text,
  summary            text,
  instrument_type    text,
  status             text,
  effective_date     date,
  jurisdiction_code  text,
  source_url         text,
  body_text          text,
  regulator_name     text,
  regulator_short    text,
  vector_score       double precision,
  fts_score          double precision,
  blended_score      double precision
)
language plpgsql
stable
security definer
set search_path = regwatch, public
as $$
declare
  qvec        vector(1024);
  qts         tsquery;
  fts_available boolean := false;
begin
  -- Parse the inputs defensively. A NULL/empty embedding falls back to
  -- pure FTS so the function still works during the Voyage backfill phase.
  begin
    if query_embedding is null or length(query_embedding) = 0 then
      qvec := null;
    else
      qvec := query_embedding::vector(1024);
    end if;
  exception when others then
    qvec := null;
  end;

  -- websearch_to_tsquery returns empty on stopword-only input; guard so the
  -- whole call doesn't degrade to "no rows".
  begin
    qts := websearch_to_tsquery('english', coalesce(query_text, ''));
    fts_available := numnode(qts) > 0;
  exception when others then
    fts_available := false;
  end;

  return query
  with candidates as (
    select
      ri.id,
      ri.citation,
      ri.slug,
      ri.title,
      ri.summary,
      ri.instrument_type,
      ri.status,
      ri.effective_date,
      ri.jurisdiction_code,
      ri.source_url,
      ri.body_text,
      r.name        as regulator_name,
      r.short_name  as regulator_short,
      case
        when qvec is not null and ri.embedding is not null
          then 1 - (ri.embedding <=> qvec)        -- cosine similarity in [0,1]
        else 0
      end as vector_score,
      case
        when fts_available
          then ts_rank_cd(ri.body_search, qts)
        else 0
      end as fts_score
    from regwatch.regulatory_items ri
    join regwatch.regulators r on r.id = ri.regulator_id
    -- Only consider items that COULD plausibly match: either embedded and
    -- vector-similar, or FTS-matched. Avoids scanning the whole corpus when
    -- both lanes are dead.
    where
      (qvec is not null and ri.embedding is not null)
      or (fts_available and ri.body_search @@ qts)
  ),
  -- Normalise FTS rank to [0,1] across the candidate set so the alpha blend
  -- is meaningful (vector cosine is already in [0,1]). max() across the
  -- candidate set is the simplest stable scaler.
  scaled as (
    select
      c.*,
      case
        when max(c.fts_score) over () > 0
          then c.fts_score / max(c.fts_score) over ()
        else 0
      end as fts_score_norm
    from candidates c
  )
  select
    s.id,
    s.citation,
    s.slug,
    s.title,
    s.summary,
    s.instrument_type,
    s.status,
    s.effective_date,
    s.jurisdiction_code,
    s.source_url,
    s.body_text,
    s.regulator_name,
    s.regulator_short,
    s.vector_score,
    s.fts_score_norm                                   as fts_score,
    alpha * s.vector_score + (1 - alpha) * s.fts_score_norm as blended_score
  from scaled s
  order by alpha * s.vector_score + (1 - alpha) * s.fts_score_norm desc
  limit match_limit;
end;
$$;

grant execute on function regwatch.match_regulatory_items(text, text, int, double precision)
  to authenticated, anon, service_role;

comment on function regwatch.match_regulatory_items(text, text, int, double precision) is
  'Hybrid FTS + vector retrieval over regulatory_items. alpha=1 = pure vector, alpha=0 = pure FTS.';


-- ===== MIGRATION: 20260610_regwatch_match_items_rpc_extend.sql =====
-- ===========================================================================
-- RegWatch — Extend match_regulatory_items RPC to return last_changed_at + topics
-- ---------------------------------------------------------------------------
-- The Search page renders RegulationRow which needs last_changed_at (for the
-- "Updated 3 days ago" line) and topics (for the topic chips). The original
-- RPC in 20260609 didn't return them. Postgres can't ALTER a function's
-- return signature, so we DROP + CREATE.
-- ===========================================================================

drop function if exists regwatch.match_regulatory_items(text, text, int, double precision);

create or replace function regwatch.match_regulatory_items(
  query_embedding text,
  query_text      text,
  match_limit     int default 6,
  alpha           double precision default 0.65
)
returns table (
  id                 uuid,
  citation           text,
  slug               text,
  title              text,
  summary            text,
  instrument_type    text,
  status             text,
  effective_date     date,
  last_changed_at    timestamptz,
  jurisdiction_code  text,
  source_url         text,
  body_text          text,
  topics             text[],
  regulator_slug     text,
  regulator_name     text,
  regulator_short    text,
  vector_score       double precision,
  fts_score          double precision,
  blended_score      double precision
)
language plpgsql
stable
security definer
set search_path = regwatch, public
as $$
declare
  qvec        vector(1024);
  qts         tsquery;
  fts_available boolean := false;
begin
  begin
    if query_embedding is null or length(query_embedding) = 0 then
      qvec := null;
    else
      qvec := query_embedding::vector(1024);
    end if;
  exception when others then
    qvec := null;
  end;

  begin
    qts := websearch_to_tsquery('english', coalesce(query_text, ''));
    fts_available := numnode(qts) > 0;
  exception when others then
    fts_available := false;
  end;

  return query
  with candidates as (
    select
      ri.id,
      ri.citation,
      ri.slug,
      ri.title,
      ri.summary,
      ri.instrument_type,
      ri.status,
      ri.effective_date,
      ri.last_changed_at,
      ri.jurisdiction_code,
      ri.source_url,
      ri.body_text,
      ri.topics,
      r.slug        as regulator_slug,
      r.name        as regulator_name,
      r.short_name  as regulator_short,
      case
        when qvec is not null and ri.embedding is not null
          then 1 - (ri.embedding <=> qvec)
        else 0
      end as vector_score,
      case
        when fts_available
          then ts_rank_cd(ri.body_search, qts)
        else 0
      end as fts_score
    from regwatch.regulatory_items ri
    join regwatch.regulators r on r.id = ri.regulator_id
    where
      (qvec is not null and ri.embedding is not null)
      or (fts_available and ri.body_search @@ qts)
  ),
  scaled as (
    select
      c.*,
      case
        when max(c.fts_score) over () > 0
          then c.fts_score / max(c.fts_score) over ()
        else 0
      end as fts_score_norm
    from candidates c
  )
  select
    s.id,
    s.citation,
    s.slug,
    s.title,
    s.summary,
    s.instrument_type,
    s.status,
    s.effective_date,
    s.last_changed_at,
    s.jurisdiction_code,
    s.source_url,
    s.body_text,
    s.topics,
    s.regulator_slug,
    s.regulator_name,
    s.regulator_short,
    s.vector_score,
    s.fts_score_norm                                       as fts_score,
    alpha * s.vector_score + (1 - alpha) * s.fts_score_norm as blended_score
  from scaled s
  order by alpha * s.vector_score + (1 - alpha) * s.fts_score_norm desc
  limit match_limit;
end;
$$;

grant execute on function regwatch.match_regulatory_items(text, text, int, double precision)
  to authenticated, anon, service_role;

comment on function regwatch.match_regulatory_items(text, text, int, double precision) is
  'Hybrid FTS + vector retrieval over regulatory_items. alpha=1 = pure vector, alpha=0 = pure FTS. Returns RegulationListItem-compatible columns.';


-- ===== MIGRATION: 20260612_regwatch_asset_hierarchy.sql =====
-- ===========================================================================
-- RegWatch — Asset hierarchy (Phase 1 of the Asset Management feature)
-- ---------------------------------------------------------------------------
-- Per-org asset tree, self-referential through `parent_id`, with a configurable
-- label per level so an O&G org sees "Process Unit" where a hospital sees
-- "Department". Five fixed levels (L2-L5 + optional L6); L1 is the
-- organization itself and lives in regwatch.organizations.
--
-- Levels:
--   L2  Site                 (refinery, FPSO, hospital, plant, wind farm)
--   L3  Area / Process Unit  (CDU, paint booth, ICU, turbine string)
--   L4  Asset Class          (centrifugal pump, MRI scanner, transformer)
--   L5  Asset / Tag          (P-101A, MR-3, WTG-12)
--   L6  Component (opt-in)   (PSV, gearbox, sensor train) — Enterprise tier
--
-- Reuses the canonical org-member RLS pattern: SELECT for any member,
-- INSERT/UPDATE/DELETE for org admins only (new is_org_admin() helper).
-- ===========================================================================

-- ===========================================================================
-- Helper: does the calling user have admin/owner role in this org?
-- Mirrors the ensureAdmin() server-side check; used by every admin-write RLS
-- policy on the new tables.
-- ===========================================================================
create or replace function regwatch.is_org_admin(target_org uuid)
returns boolean
language sql
security definer
stable
set search_path = regwatch, public
as $$
  select exists (
    select 1
    from regwatch.organization_members m
    where m.organization_id = target_org
      and m.user_id = auth.uid()
      and m.role in ('owner', 'admin')
  );
$$;

grant execute on function regwatch.is_org_admin(uuid) to authenticated;

-- ===========================================================================
-- asset_hierarchy_config — one row per org; configurable level labels
-- ===========================================================================
create table regwatch.asset_hierarchy_config (
  id                uuid primary key default gen_random_uuid(),
  organization_id  uuid not null references regwatch.organizations(id) on delete cascade,

  level_2_label    text not null default 'Site',
  level_3_label    text not null default 'Area',
  level_4_label    text not null default 'Asset Class',
  level_5_label    text not null default 'Asset',
  level_6_enabled  boolean not null default false,
  level_6_label    text default 'Component',

  -- Industry starter pack used to seed L3 + L4 nodes (one of:
  -- 'iso-14224', 'gmdn', 'ata-100', 'rds-pp', 'isa-95', or NULL for empty).
  starter_pack    text,

  created_at      timestamptz not null default now(),
  updated_at      timestamptz not null default now(),

  unique (organization_id)
);

create trigger asset_hierarchy_config_set_updated_at
  before update on regwatch.asset_hierarchy_config
  for each row execute function regwatch.set_updated_at();

-- ===========================================================================
-- assets — self-referential tree
-- ===========================================================================
create table regwatch.assets (
  id                uuid primary key default gen_random_uuid(),
  organization_id  uuid not null references regwatch.organizations(id) on delete cascade,
  parent_id        uuid references regwatch.assets(id) on delete cascade,
  level            smallint not null check (level between 2 and 6),

  name             text not null,
  -- External code: SAP PM functional location, RDS-PP designation,
  -- GMDN code, asset tag #, etc. Allows customers to plug into their EAM.
  code             text,
  -- Either free-text or a value drawn from the active starter pack
  -- (e.g. 'centrifugal-pump' from ISO 14224).
  asset_type       text,
  -- Defaults to the Site's jurisdiction; overrideable at any level.
  jurisdiction_code text,

  substances_cas   text[] not null default '{}',
  permits          jsonb not null default '{}'::jsonb,
  tags             text[] not null default '{}',
  metadata         jsonb not null default '{}'::jsonb,

  created_by       uuid references auth.users(id) on delete set null,
  created_at       timestamptz not null default now(),
  updated_at       timestamptz not null default now(),
  archived_at      timestamptz
);

create index assets_org_level_idx     on regwatch.assets (organization_id, level);
create index assets_parent_idx        on regwatch.assets (parent_id);
create index assets_org_code_idx      on regwatch.assets (organization_id, code) where code is not null;
create index assets_org_archived_idx  on regwatch.assets (organization_id) where archived_at is null;

create trigger assets_set_updated_at
  before update on regwatch.assets
  for each row execute function regwatch.set_updated_at();

-- ===========================================================================
-- RLS — members read, admins write
-- ===========================================================================
alter table regwatch.asset_hierarchy_config enable row level security;
alter table regwatch.assets                  enable row level security;

drop policy if exists asset_hierarchy_config_member_read on regwatch.asset_hierarchy_config;
create policy asset_hierarchy_config_member_read on regwatch.asset_hierarchy_config
  for select to authenticated
  using (regwatch.is_org_member(organization_id));

drop policy if exists asset_hierarchy_config_admin_write on regwatch.asset_hierarchy_config;
create policy asset_hierarchy_config_admin_write on regwatch.asset_hierarchy_config
  for insert to authenticated
  with check (regwatch.is_org_admin(organization_id));

drop policy if exists asset_hierarchy_config_admin_update on regwatch.asset_hierarchy_config;
create policy asset_hierarchy_config_admin_update on regwatch.asset_hierarchy_config
  for update to authenticated
  using (regwatch.is_org_member(organization_id))
  with check (regwatch.is_org_admin(organization_id));

drop policy if exists assets_member_read on regwatch.assets;
create policy assets_member_read on regwatch.assets
  for select to authenticated
  using (regwatch.is_org_member(organization_id));

drop policy if exists assets_admin_insert on regwatch.assets;
create policy assets_admin_insert on regwatch.assets
  for insert to authenticated
  with check (regwatch.is_org_admin(organization_id));

drop policy if exists assets_admin_update on regwatch.assets;
create policy assets_admin_update on regwatch.assets
  for update to authenticated
  using (regwatch.is_org_member(organization_id))
  with check (regwatch.is_org_admin(organization_id));

drop policy if exists assets_admin_delete on regwatch.assets;
create policy assets_admin_delete on regwatch.assets
  for delete to authenticated
  using (regwatch.is_org_admin(organization_id));

-- ===========================================================================
-- Grants
-- ===========================================================================
grant select on regwatch.asset_hierarchy_config to authenticated;
grant insert, update on regwatch.asset_hierarchy_config to authenticated;

grant select on regwatch.assets to authenticated;
grant insert, update, delete on regwatch.assets to authenticated;


-- ===== MIGRATION: 20260613_regwatch_compliance_obligations.sql =====
-- ===========================================================================
-- RegWatch — compliance_obligations (Phase 1 of Asset Management)
-- ---------------------------------------------------------------------------
-- The workflow primitive that ties an asset to a regulation (or specific
-- clause within one), with an assigned reviewer, a state machine, and
-- admin-locked grading.
--
-- Locked columns (severity, compliance_status, admin_signed_off_at,
-- compliance_attested_until) are enforced by a BEFORE UPDATE trigger that
-- raises if the caller isn't an org admin. The server actions provide
-- the friendly error; this trigger is the floor of correctness so a hand-
-- crafted PATCH from the network tab can't bypass the gate.
-- ===========================================================================

-- ---------------------------------------------------------------------------
-- Enums
-- ---------------------------------------------------------------------------
create type regwatch.obligation_severity as enum (
  'negligible', 'marginal', 'moderate', 'critical', 'catastrophic'
);

create type regwatch.obligation_compliance_status as enum (
  'unknown', 'non-compliant', 'at-risk', 'compliant'
);

create type regwatch.obligation_review_status as enum (
  'open',
  'awaiting-triage',
  'in-review',
  'pending-approval',
  'verified',
  'closed',
  'not-applicable'
);

create type regwatch.obligation_review_cadence as enum (
  'none', 'quarterly', 'semi-annually', 'annually', 'custom'
);

-- ---------------------------------------------------------------------------
-- compliance_obligations
-- ---------------------------------------------------------------------------
create table regwatch.compliance_obligations (
  id                       uuid primary key default gen_random_uuid(),
  organization_id          uuid not null references regwatch.organizations(id) on delete cascade,

  -- Attachment: required asset, optional regulation (nullable for clause-
  -- only obligations created from internal-only requirements), optional
  -- clause text/anchor for pinning a specific section of a long regulation.
  asset_id                 uuid not null references regwatch.assets(id) on delete cascade,
  regulatory_item_id       uuid references regwatch.regulatory_items(id) on delete set null,
  clause_text              text,
  clause_anchor            text,

  -- Admin-locked grading (enforced by trigger below)
  severity                 regwatch.obligation_severity not null default 'moderate',
  compliance_status        regwatch.obligation_compliance_status not null default 'unknown',

  -- Workflow
  assigned_reviewer_user_id uuid references auth.users(id) on delete set null,
  review_status            regwatch.obligation_review_status not null default 'open',
  review_due_at            timestamptz,
  review_completed_at      timestamptz,
  -- Structured review payload: applicability, rationale, evidence_path,
  -- redlines, etc. Free-form so reviewers can capture what they need.
  review_notes             jsonb not null default '{}'::jsonb,
  -- Storage path of the mandatory evidence file uploaded at review
  -- completion (private regwatch-documents bucket).
  evidence_file_path       text,

  -- Re-review cadence — admin sets at sign-off; cron auto-creates next task.
  review_cadence           regwatch.obligation_review_cadence not null default 'none',
  review_cadence_custom_days int,
  compliance_attested_until timestamptz,

  -- Admin sign-off (21 CFR Part 11 style: identity + reason + timestamp)
  admin_signed_off_at      timestamptz,
  admin_signed_off_by      uuid references auth.users(id) on delete set null,
  signoff_rationale        text,

  created_by               uuid references auth.users(id) on delete set null,
  created_at               timestamptz not null default now(),
  updated_at               timestamptz not null default now(),

  -- One obligation per (org, asset, regulation, clause) tuple. Clause
  -- anchors that are NULL participate in the uniqueness check so a single
  -- "whole regulation" obligation can't be created twice.
  unique (organization_id, asset_id, regulatory_item_id, clause_anchor)
);

create index obligations_org_status_idx
  on regwatch.compliance_obligations (organization_id, review_status);
create index obligations_reviewer_open_idx
  on regwatch.compliance_obligations (assigned_reviewer_user_id)
  where review_status in ('awaiting-triage', 'in-review');
create index obligations_reg_item_idx
  on regwatch.compliance_obligations (regulatory_item_id)
  where regulatory_item_id is not null;
create index obligations_asset_idx
  on regwatch.compliance_obligations (asset_id);
create index obligations_attested_until_idx
  on regwatch.compliance_obligations (compliance_attested_until)
  where compliance_attested_until is not null;

create trigger compliance_obligations_set_updated_at
  before update on regwatch.compliance_obligations
  for each row execute function regwatch.set_updated_at();

-- ---------------------------------------------------------------------------
-- Admin-lock trigger
-- ---------------------------------------------------------------------------
-- The trigger raises if a non-admin attempts to change any of:
--   severity, compliance_status, admin_signed_off_at, admin_signed_off_by,
--   signoff_rationale, compliance_attested_until, review_cadence,
--   review_cadence_custom_days.
-- Reviewers may freely change review_status (via permitted state
-- transitions enforced server-side), review_completed_at, review_notes,
-- evidence_file_path, and assigned_reviewer_user_id (re-self-assignment
-- for example).
-- ---------------------------------------------------------------------------
create or replace function regwatch.enforce_obligation_admin_locks()
returns trigger
language plpgsql
security definer
set search_path = regwatch, public
as $$
begin
  if (
       old.severity                 is distinct from new.severity
    or old.compliance_status        is distinct from new.compliance_status
    or old.admin_signed_off_at      is distinct from new.admin_signed_off_at
    or old.admin_signed_off_by      is distinct from new.admin_signed_off_by
    or old.signoff_rationale        is distinct from new.signoff_rationale
    or old.compliance_attested_until is distinct from new.compliance_attested_until
    or old.review_cadence           is distinct from new.review_cadence
    or old.review_cadence_custom_days is distinct from new.review_cadence_custom_days
  ) and not regwatch.is_org_admin(new.organization_id) then
    raise exception
      'Only org admins can modify severity, compliance_status, sign-off, or review cadence (regwatch.obligation_admin_locks)';
  end if;
  return new;
end;
$$;

create trigger obligation_admin_locks
  before update on regwatch.compliance_obligations
  for each row execute function regwatch.enforce_obligation_admin_locks();

-- ---------------------------------------------------------------------------
-- RLS
-- ---------------------------------------------------------------------------
alter table regwatch.compliance_obligations enable row level security;

drop policy if exists obligations_member_read on regwatch.compliance_obligations;
create policy obligations_member_read on regwatch.compliance_obligations
  for select to authenticated
  using (regwatch.is_org_member(organization_id));

-- Insert: admins create; the reviewer assignment + state changes flow
-- through UPDATE, gated by the trigger above.
drop policy if exists obligations_admin_insert on regwatch.compliance_obligations;
create policy obligations_admin_insert on regwatch.compliance_obligations
  for insert to authenticated
  with check (regwatch.is_org_admin(organization_id));

-- Update: any org member can update the row; the trigger above raises if
-- they try to change a locked column without admin role. Server actions
-- also strip locked fields before sending; the trigger is the safety net.
drop policy if exists obligations_member_update on regwatch.compliance_obligations;
create policy obligations_member_update on regwatch.compliance_obligations
  for update to authenticated
  using (regwatch.is_org_member(organization_id))
  with check (regwatch.is_org_member(organization_id));

drop policy if exists obligations_admin_delete on regwatch.compliance_obligations;
create policy obligations_admin_delete on regwatch.compliance_obligations
  for delete to authenticated
  using (regwatch.is_org_admin(organization_id));

-- ---------------------------------------------------------------------------
-- Grants
-- ---------------------------------------------------------------------------
grant select on regwatch.compliance_obligations to authenticated;
grant insert, update, delete on regwatch.compliance_obligations to authenticated;


-- ===== MIGRATION: 20260614_rate_limits.sql =====
-- Rate limiting for public/edge endpoints (F2/F3).
-- Fixed-window counter shared across serverless instances. Called server-side
-- via the service-role client (see src/lib/rate-limit.ts). APPLY THIS in the
-- Supabase SQL editor — until then the helper fails open (allows traffic).

create table if not exists public.rate_limits (
  bucket        text        not null,
  identifier    text        not null,
  window_start  timestamptz not null,
  count         integer     not null default 0,
  primary key (bucket, identifier, window_start)
);

-- Old windows are dead weight; index for cheap cleanup.
create index if not exists rate_limits_window_idx on public.rate_limits (window_start);

-- Atomically increments the current fixed window's counter and returns whether
-- the request is still within budget (count <= p_max).
create or replace function public.check_rate_limit(
  p_bucket text,
  p_identifier text,
  p_max integer,
  p_window_seconds integer
) returns boolean
language plpgsql
security definer
set search_path = public
as $$
declare
  v_window timestamptz := to_timestamp(
    floor(extract(epoch from now()) / p_window_seconds) * p_window_seconds
  );
  v_count integer;
begin
  insert into public.rate_limits (bucket, identifier, window_start, count)
  values (p_bucket, p_identifier, v_window, 1)
  on conflict (bucket, identifier, window_start)
  do update set count = public.rate_limits.count + 1
  returning count into v_count;

  return v_count <= p_max;
end;
$$;

-- RLS on the table; the function is security-definer and the app calls it via
-- the service role, so no direct table grants to anon/authenticated are needed.
alter table public.rate_limits enable row level security;


-- ===== MIGRATION: 20260614_regwatch_internal_documents.sql =====
-- ===========================================================================
-- RegWatch — internal_documents + regulation links (Phase 1 of Asset Mgmt)
-- ---------------------------------------------------------------------------
-- Org-private repository for SOPs, policies, permits, work instructions, etc.
-- Each document carries an owner_user_id who is notified when any linked
-- external regulation changes. Junction table internal_document_regulation_links
-- uses Veeva-style version pinning: each link snapshots a content hash at
-- link time; when the regulation updates, the link is marked superseded and
-- a fresh link row is auto-created against the new version (Phase 3 cron).
--
-- Files live in a private Supabase Storage bucket "regwatch-documents",
-- pathed as <organization_id>/<internal_document_id>/<uuid>-<filename>.
-- Storage RLS uses the first path segment to check org membership.
-- ===========================================================================

-- ---------------------------------------------------------------------------
-- Enums
-- ---------------------------------------------------------------------------
create type regwatch.internal_document_kind as enum (
  'sop',
  'policy',
  'permit',
  'work-instruction',
  'training-material',
  'validation-protocol',
  'risk-assessment',
  'other'
);

create type regwatch.internal_document_status as enum (
  'draft', 'active', 'superseded', 'retired'
);

-- ---------------------------------------------------------------------------
-- internal_documents
-- ---------------------------------------------------------------------------
create table regwatch.internal_documents (
  id                uuid primary key default gen_random_uuid(),
  organization_id  uuid not null references regwatch.organizations(id) on delete cascade,

  title             text not null,
  doc_kind          regwatch.internal_document_kind not null default 'sop',
  internal_code     text,        -- customer's SOP number, e.g. SOP-EHS-014
  version           text,
  effective_date    date,
  next_review_date  date,

  -- Owner is the person notified on linked-regulation changes. owner_role
  -- is a v2 forward-compat field for role-based ownership (assignments
  -- survive personnel turnover) — Phase 1 just collects the value.
  owner_user_id     uuid references auth.users(id) on delete set null,
  owner_role        text,

  description       text,

  -- Supabase Storage metadata
  file_path         text,        -- regwatch-documents/<org>/<doc>/<uuid>-<filename>
  file_name         text,
  file_size         bigint,
  mime_type         text,

  status            regwatch.internal_document_status not null default 'active',

  created_by        uuid references auth.users(id) on delete set null,
  created_at        timestamptz not null default now(),
  updated_at        timestamptz not null default now()
);

create index internal_docs_org_idx          on regwatch.internal_documents (organization_id);
create index internal_docs_owner_idx        on regwatch.internal_documents (owner_user_id);
create index internal_docs_org_status_idx   on regwatch.internal_documents (organization_id, status);

create trigger internal_documents_set_updated_at
  before update on regwatch.internal_documents
  for each row execute function regwatch.set_updated_at();

-- ---------------------------------------------------------------------------
-- internal_document_regulation_links
-- ---------------------------------------------------------------------------
create table regwatch.internal_document_regulation_links (
  id                       uuid primary key default gen_random_uuid(),
  organization_id          uuid not null references regwatch.organizations(id) on delete cascade,

  internal_document_id     uuid not null references regwatch.internal_documents(id) on delete cascade,
  regulatory_item_id       uuid not null references regwatch.regulatory_items(id) on delete cascade,
  clause_anchor            text,
  link_rationale           text,

  -- Snapshot of regulatory_items.last_changed_at + a hash of content at link
  -- time, so the link captures "we linked to THIS version". On regulation
  -- update, Phase 3 cron sets superseded_at and creates a fresh row.
  linked_at_item_version   text,

  superseded_at            timestamptz,

  created_by               uuid references auth.users(id) on delete set null,
  created_at               timestamptz not null default now()
);

-- One ACTIVE link per (org, doc, regulation, clause). Superseded links
-- accumulate as history.
create unique index internal_docs_link_active_uq
  on regwatch.internal_document_regulation_links
       (organization_id, internal_document_id, regulatory_item_id, coalesce(clause_anchor, ''))
  where superseded_at is null;

create index internal_docs_link_doc_idx
  on regwatch.internal_document_regulation_links (internal_document_id)
  where superseded_at is null;
create index internal_docs_link_reg_idx
  on regwatch.internal_document_regulation_links (regulatory_item_id)
  where superseded_at is null;

-- ---------------------------------------------------------------------------
-- RLS
-- ---------------------------------------------------------------------------
alter table regwatch.internal_documents enable row level security;
alter table regwatch.internal_document_regulation_links enable row level security;

drop policy if exists internal_docs_member_read on regwatch.internal_documents;
create policy internal_docs_member_read on regwatch.internal_documents
  for select to authenticated
  using (regwatch.is_org_member(organization_id));

drop policy if exists internal_docs_admin_insert on regwatch.internal_documents;
create policy internal_docs_admin_insert on regwatch.internal_documents
  for insert to authenticated
  with check (regwatch.is_org_admin(organization_id));

drop policy if exists internal_docs_admin_update on regwatch.internal_documents;
create policy internal_docs_admin_update on regwatch.internal_documents
  for update to authenticated
  using (regwatch.is_org_member(organization_id))
  with check (regwatch.is_org_admin(organization_id));

drop policy if exists internal_docs_admin_delete on regwatch.internal_documents;
create policy internal_docs_admin_delete on regwatch.internal_documents
  for delete to authenticated
  using (regwatch.is_org_admin(organization_id));

-- Links: any org member can read; any org member can create/delete (admins
-- control documents, reviewers wire them up).
drop policy if exists internal_docs_link_member_read on regwatch.internal_document_regulation_links;
create policy internal_docs_link_member_read on regwatch.internal_document_regulation_links
  for select to authenticated
  using (regwatch.is_org_member(organization_id));

drop policy if exists internal_docs_link_member_insert on regwatch.internal_document_regulation_links;
create policy internal_docs_link_member_insert on regwatch.internal_document_regulation_links
  for insert to authenticated
  with check (regwatch.is_org_member(organization_id));

drop policy if exists internal_docs_link_member_update on regwatch.internal_document_regulation_links;
create policy internal_docs_link_member_update on regwatch.internal_document_regulation_links
  for update to authenticated
  using (regwatch.is_org_member(organization_id))
  with check (regwatch.is_org_member(organization_id));

drop policy if exists internal_docs_link_member_delete on regwatch.internal_document_regulation_links;
create policy internal_docs_link_member_delete on regwatch.internal_document_regulation_links
  for delete to authenticated
  using (regwatch.is_org_member(organization_id));

-- ---------------------------------------------------------------------------
-- Grants
-- ---------------------------------------------------------------------------
grant select on regwatch.internal_documents to authenticated;
grant insert, update, delete on regwatch.internal_documents to authenticated;
grant select on regwatch.internal_document_regulation_links to authenticated;
grant insert, update, delete on regwatch.internal_document_regulation_links to authenticated;

-- ===========================================================================
-- Supabase Storage — regwatch-documents bucket
-- ===========================================================================
insert into storage.buckets (id, name, public)
values ('regwatch-documents', 'regwatch-documents', false)
on conflict (id) do nothing;

-- Storage RLS — folder name [1] is the organization_id; check membership.
drop policy if exists regwatch_docs_member_select on storage.objects;
create policy regwatch_docs_member_select on storage.objects
  for select to authenticated
  using (
    bucket_id = 'regwatch-documents'
    and (storage.foldername(name))[1] is not null
    and regwatch.is_org_member(((storage.foldername(name))[1])::uuid)
  );

drop policy if exists regwatch_docs_member_insert on storage.objects;
create policy regwatch_docs_member_insert on storage.objects
  for insert to authenticated
  with check (
    bucket_id = 'regwatch-documents'
    and (storage.foldername(name))[1] is not null
    and regwatch.is_org_member(((storage.foldername(name))[1])::uuid)
  );

drop policy if exists regwatch_docs_admin_delete on storage.objects;
create policy regwatch_docs_admin_delete on storage.objects
  for delete to authenticated
  using (
    bucket_id = 'regwatch-documents'
    and (storage.foldername(name))[1] is not null
    and regwatch.is_org_admin(((storage.foldername(name))[1])::uuid)
  );


-- ===== MIGRATION: 20260615_regwatch_asset_mgmt_service_role_grants.sql =====
-- ===========================================================================
-- RegWatch — Service-role grants on the Phase 1 Asset Management tables
-- ---------------------------------------------------------------------------
-- The initial regwatch migration granted `service_role` ALL on every table
-- that existed at that time, but those grants don't cascade to tables
-- created in later migrations. Phase 1 added five new tables; this catches
-- the service-role client up so server actions (which write via the
-- service-role client to bypass RLS) actually have privileges.
--
-- Symptom this fixes: "permission denied for table assets" when an admin
-- clicks "+ Add Site" on /regwatch/assets/setup.
-- ===========================================================================

grant all on regwatch.assets                                  to service_role;
grant all on regwatch.asset_hierarchy_config                  to service_role;
grant all on regwatch.compliance_obligations                  to service_role;
grant all on regwatch.internal_documents                      to service_role;
grant all on regwatch.internal_document_regulation_links      to service_role;

-- Also grant execute on the new is_org_admin helper to service_role so the
-- admin-lock trigger (security definer, but called from service-role-
-- initiated updates) can resolve cleanly.
grant execute on function regwatch.is_org_admin(uuid) to service_role;


-- ===== MIGRATION: 20260616_regwatch_obligation_state_history.sql =====
-- ===========================================================================
-- RegWatch — obligation_state_history (Phase 2 of Asset Management)
-- ---------------------------------------------------------------------------
-- Audit trail for the compliance_obligations state machine. Every transition
-- (including the synthetic 'open' → 'awaiting-triage' on first assignment)
-- writes a row here. Used for:
--   1. The state-history timeline on the obligation detail page.
--   2. Audit exports — every transition has an actor + timestamp +
--      optional notes (sign-off rationale, kick-back reason, NA rationale).
--   3. SLA reporting in Phase 4 (time-in-state).
--
-- An AFTER UPDATE trigger on compliance_obligations records the transition
-- whenever review_status changes. INSERT also writes a creation event so
-- the timeline starts from the open-state row.
-- ===========================================================================

create table regwatch.obligation_state_history (
  id              uuid primary key default gen_random_uuid(),
  organization_id uuid not null references regwatch.organizations(id) on delete cascade,
  obligation_id   uuid not null references regwatch.compliance_obligations(id) on delete cascade,

  -- The transition itself
  from_status     regwatch.obligation_review_status,  -- null on the create row
  to_status       regwatch.obligation_review_status not null,

  -- Actor — set by trigger from auth.uid() when available; server actions
  -- that need to pass an explicit actor write the row themselves before
  -- the UPDATE so the trigger sees no row to add.
  actor_user_id   uuid references auth.users(id) on delete set null,

  -- Optional metadata: rationale on N/A, kick-back notes, sign-off rationale.
  notes           text,
  metadata        jsonb not null default '{}'::jsonb,

  created_at      timestamptz not null default now()
);

create index obligation_state_history_obligation_idx
  on regwatch.obligation_state_history (obligation_id, created_at desc);
create index obligation_state_history_org_idx
  on regwatch.obligation_state_history (organization_id, created_at desc);

-- ---------------------------------------------------------------------------
-- Trigger function
-- ---------------------------------------------------------------------------
-- AFTER INSERT records the initial state.
-- AFTER UPDATE records the transition when review_status changes.
-- The server action writes the actor by setting a local config var:
--   select set_config('regwatch.actor', auth.uid()::text, true);
-- Falls back to auth.uid() (when called from RLS-policy SSR context).
-- ---------------------------------------------------------------------------
create or replace function regwatch.record_obligation_state_history()
returns trigger
language plpgsql
security definer
set search_path = regwatch, public
as $$
declare
  actor uuid;
begin
  -- Resolve actor: explicit config var wins, otherwise auth.uid().
  begin
    actor := nullif(current_setting('regwatch.actor', true), '')::uuid;
  exception when others then
    actor := null;
  end;
  if actor is null then
    actor := auth.uid();
  end if;

  if tg_op = 'INSERT' then
    insert into regwatch.obligation_state_history
      (organization_id, obligation_id, from_status, to_status, actor_user_id)
    values (new.organization_id, new.id, null, new.review_status, actor);
    return new;
  end if;

  if tg_op = 'UPDATE' and old.review_status is distinct from new.review_status then
    insert into regwatch.obligation_state_history
      (organization_id, obligation_id, from_status, to_status, actor_user_id,
       notes, metadata)
    values (
      new.organization_id,
      new.id,
      old.review_status,
      new.review_status,
      actor,
      case
        when new.review_status = 'verified' then new.signoff_rationale
        else null
      end,
      jsonb_build_object(
        'severity_at_transition', new.severity,
        'compliance_status_at_transition', new.compliance_status
      )
    );
  end if;
  return new;
end;
$$;

create trigger obligation_state_history_insert
  after insert on regwatch.compliance_obligations
  for each row execute function regwatch.record_obligation_state_history();

create trigger obligation_state_history_update
  after update on regwatch.compliance_obligations
  for each row execute function regwatch.record_obligation_state_history();

-- ---------------------------------------------------------------------------
-- RLS — members can read their org's history; only the trigger writes.
-- ---------------------------------------------------------------------------
alter table regwatch.obligation_state_history enable row level security;

drop policy if exists obligation_state_history_member_read on regwatch.obligation_state_history;
create policy obligation_state_history_member_read on regwatch.obligation_state_history
  for select to authenticated
  using (regwatch.is_org_member(organization_id));

-- ---------------------------------------------------------------------------
-- Grants — service-role gets ALL (so the trigger inserts succeed);
-- authenticated gets SELECT only (writes happen via trigger).
-- ---------------------------------------------------------------------------
grant select on regwatch.obligation_state_history to authenticated;
grant all    on regwatch.obligation_state_history to service_role;
grant execute on function regwatch.record_obligation_state_history()
  to service_role, authenticated;


-- ===== MIGRATION: 20260617_regwatch_internal_document_asset_links.sql =====
-- ===========================================================================
-- RegWatch — internal_document_asset_links
-- ---------------------------------------------------------------------------
-- Pin an internal document (SOP / policy / permit / etc.) to one or more
-- assets in the hierarchy. Mirrors internal_document_regulation_links but
-- the other side is an asset, not a regulation.
--
-- Why a separate table from internal_document_regulation_links?
--   Different semantics (asset doesn't supersede), different RLS shape
--   (no version pinning), and the natural fan-out is different (one doc
--   typically attaches to many assets; one doc rarely attaches to many
--   regulations the same way).
-- ===========================================================================

create table regwatch.internal_document_asset_links (
  id                       uuid primary key default gen_random_uuid(),
  organization_id          uuid not null references regwatch.organizations(id) on delete cascade,

  internal_document_id     uuid not null references regwatch.internal_documents(id) on delete cascade,
  asset_id                 uuid not null references regwatch.assets(id) on delete cascade,
  link_rationale           text,

  created_by               uuid references auth.users(id) on delete set null,
  created_at               timestamptz not null default now(),

  -- One link per (org, doc, asset) tuple.
  unique (organization_id, internal_document_id, asset_id)
);

create index internal_doc_asset_doc_idx
  on regwatch.internal_document_asset_links (internal_document_id);
create index internal_doc_asset_asset_idx
  on regwatch.internal_document_asset_links (asset_id);

-- ---------------------------------------------------------------------------
-- RLS — any org member can read; any org member can wire links up. (Document
-- creation itself stays admin-only via internal_documents policies.)
-- ---------------------------------------------------------------------------
alter table regwatch.internal_document_asset_links enable row level security;

drop policy if exists internal_doc_asset_member_read on regwatch.internal_document_asset_links;
create policy internal_doc_asset_member_read on regwatch.internal_document_asset_links
  for select to authenticated
  using (regwatch.is_org_member(organization_id));

drop policy if exists internal_doc_asset_member_insert on regwatch.internal_document_asset_links;
create policy internal_doc_asset_member_insert on regwatch.internal_document_asset_links
  for insert to authenticated
  with check (regwatch.is_org_member(organization_id));

drop policy if exists internal_doc_asset_member_delete on regwatch.internal_document_asset_links;
create policy internal_doc_asset_member_delete on regwatch.internal_document_asset_links
  for delete to authenticated
  using (regwatch.is_org_member(organization_id));

-- ---------------------------------------------------------------------------
-- Grants — both authenticated AND service_role (see feedback memory:
-- the schema-wide grant in 20260602 doesn't cascade to later tables).
-- ---------------------------------------------------------------------------
grant select, insert, delete on regwatch.internal_document_asset_links to authenticated;
grant all on regwatch.internal_document_asset_links to service_role;


-- ===== MIGRATION: 20260618_regwatch_obligation_notifications.sql =====
-- ===========================================================================
-- RegWatch — Obligation notification queue + change-detection triggers
-- ---------------------------------------------------------------------------
-- Closes the inward-facing notification loop:
--   1. Reviewer is notified when an obligation is assigned to them.
--   2. Reviewer is notified when the regulation behind their open obligation
--      changes (regulatory_items.last_changed_at advances).
--   3. Internal-document owner is notified when any linked regulation
--      changes — AND the active link row is automatically marked
--      superseded + a fresh link row is inserted against the new version
--      (Veeva-style version pinning enforced server-side, not just at
--      link-create time).
--   4. Admins are notified when an obligation moves to pending-approval.
--   5. The original reviewer is notified when their submission is signed
--      off (or kicked back).
--
-- Implementation: BEFORE/AFTER triggers ENQUEUE rows; the
-- regwatch-notify-obligations cron drains them and fans out via Brevo +
-- Web Push, sharing the existing alert_deliveries idempotency log.
-- ===========================================================================

-- ---------------------------------------------------------------------------
-- Enum + queue table
-- ---------------------------------------------------------------------------
create type regwatch.obligation_notification_kind as enum (
  'obligation_assigned',
  'regulation_changed_for_obligation',
  'regulation_changed_for_doc',
  'obligation_pending_approval',
  'obligation_signed_off',
  'obligation_kicked_back'
);

create table regwatch.obligation_notification_queue (
  id                  uuid primary key default gen_random_uuid(),
  organization_id     uuid not null references regwatch.organizations(id) on delete cascade,
  recipient_user_id   uuid not null references auth.users(id) on delete cascade,
  kind                regwatch.obligation_notification_kind not null,

  -- Subjects of the notification — all nullable; the cron picks the
  -- right set per kind. The cron joins to the fresh row at send time so
  -- we don't store denormalised state that can go stale.
  obligation_id           uuid references regwatch.compliance_obligations(id) on delete cascade,
  regulatory_item_id      uuid references regwatch.regulatory_items(id) on delete cascade,
  internal_document_id    uuid references regwatch.internal_documents(id) on delete cascade,

  -- Free-form payload (kick-back notes, prior version hash, etc.).
  payload                 jsonb not null default '{}'::jsonb,

  enqueued_at             timestamptz not null default now(),
  sent_at                 timestamptz,
  failed_at               timestamptz,
  fail_count              int not null default 0,
  last_error              text
);

create index obligation_notif_queue_pending_idx
  on regwatch.obligation_notification_queue (enqueued_at)
  where sent_at is null and (failed_at is null or fail_count < 5);

create index obligation_notif_queue_org_idx
  on regwatch.obligation_notification_queue (organization_id, enqueued_at desc);

-- ---------------------------------------------------------------------------
-- RLS — members read their org's queue (helps the dashboard later); cron
-- + service-role writes.
-- ---------------------------------------------------------------------------
alter table regwatch.obligation_notification_queue enable row level security;

drop policy if exists obligation_notif_queue_member_read on regwatch.obligation_notification_queue;
create policy obligation_notif_queue_member_read on regwatch.obligation_notification_queue
  for select to authenticated
  using (regwatch.is_org_member(organization_id));

-- ---------------------------------------------------------------------------
-- Grants — explicit per the new-table-grant rule.
-- ---------------------------------------------------------------------------
grant select on regwatch.obligation_notification_queue to authenticated;
grant all    on regwatch.obligation_notification_queue to service_role;

-- ===========================================================================
-- Trigger 1: regulation change → fan out
-- ---------------------------------------------------------------------------
-- AFTER UPDATE on regulatory_items: when last_changed_at advances, find
-- every open obligation that pins this regulation and every active
-- internal-document link, and ENQUEUE one notification row per recipient.
-- The doc-link side ALSO supersedes the active row + inserts a fresh link
-- against the new last_changed_at version stamp so the version-pin
-- contract is enforced even when the original linker isn't around.
-- ===========================================================================
create or replace function regwatch.handle_regulation_change()
returns trigger
language plpgsql
security definer
set search_path = regwatch, public
as $$
declare
  new_version text;
begin
  -- Only act when the last_changed_at moved forward.
  if new.last_changed_at is not distinct from old.last_changed_at then
    return new;
  end if;

  new_version := new.last_changed_at::text;

  -- (a) Reviewer notifications for every open obligation pinned to this reg.
  insert into regwatch.obligation_notification_queue
    (organization_id, recipient_user_id, kind, obligation_id, regulatory_item_id, payload)
  select
    o.organization_id,
    o.assigned_reviewer_user_id,
    'regulation_changed_for_obligation',
    o.id,
    new.id,
    jsonb_build_object('new_version', new_version)
  from regwatch.compliance_obligations o
  where o.regulatory_item_id = new.id
    and o.assigned_reviewer_user_id is not null
    and o.review_status not in ('verified', 'closed', 'not-applicable');

  -- (b) Doc-owner notifications — one per linked, not-yet-superseded link.
  insert into regwatch.obligation_notification_queue
    (organization_id, recipient_user_id, kind, internal_document_id,
     regulatory_item_id, payload)
  select
    l.organization_id,
    d.owner_user_id,
    'regulation_changed_for_doc',
    l.internal_document_id,
    new.id,
    jsonb_build_object(
      'prev_version', l.linked_at_item_version,
      'new_version',  new_version
    )
  from regwatch.internal_document_regulation_links l
  join regwatch.internal_documents d on d.id = l.internal_document_id
  where l.regulatory_item_id = new.id
    and l.superseded_at is null
    and d.owner_user_id is not null;

  -- (c) Auto-supersede active link rows + insert fresh ones against the
  -- new version stamp. Loop because we need each row's prior values to
  -- build the replacement.
  insert into regwatch.internal_document_regulation_links
    (organization_id, internal_document_id, regulatory_item_id, clause_anchor,
     link_rationale, linked_at_item_version, created_by)
  select
    l.organization_id,
    l.internal_document_id,
    l.regulatory_item_id,
    l.clause_anchor,
    l.link_rationale,
    new_version,
    l.created_by
  from regwatch.internal_document_regulation_links l
  where l.regulatory_item_id = new.id
    and l.superseded_at is null;

  update regwatch.internal_document_regulation_links
     set superseded_at = now()
   where regulatory_item_id = new.id
     and superseded_at is null
     and linked_at_item_version is distinct from new_version;

  return new;
end;
$$;

drop trigger if exists regulatory_items_notify_on_change on regwatch.regulatory_items;
create trigger regulatory_items_notify_on_change
  after update on regwatch.regulatory_items
  for each row execute function regwatch.handle_regulation_change();

-- ===========================================================================
-- Trigger 2: obligation state change → fan out
-- ---------------------------------------------------------------------------
-- AFTER UPDATE on compliance_obligations:
--   - on assignment (assigned_reviewer_user_id set): notify the reviewer.
--   - state → pending-approval: notify every org admin.
--   - state → verified: notify the reviewer (+ doc owners on linked docs).
--   - state → in-review FROM pending-approval (admin kick-back): notify reviewer.
-- ===========================================================================
create or replace function regwatch.handle_obligation_change()
returns trigger
language plpgsql
security definer
set search_path = regwatch, public
as $$
begin
  -- Newly assigned reviewer (existing row had no assignee or a different one).
  if new.assigned_reviewer_user_id is not null
     and (
       old.assigned_reviewer_user_id is null
       or old.assigned_reviewer_user_id is distinct from new.assigned_reviewer_user_id
     )
  then
    insert into regwatch.obligation_notification_queue
      (organization_id, recipient_user_id, kind, obligation_id,
       regulatory_item_id, payload)
    values (
      new.organization_id,
      new.assigned_reviewer_user_id,
      'obligation_assigned',
      new.id,
      new.regulatory_item_id,
      '{}'::jsonb
    );
  end if;

  -- State transition fan-out.
  if old.review_status is distinct from new.review_status then
    -- pending-approval → notify every owner+admin of the org.
    if new.review_status = 'pending-approval' then
      insert into regwatch.obligation_notification_queue
        (organization_id, recipient_user_id, kind, obligation_id,
         regulatory_item_id, payload)
      select
        new.organization_id,
        m.user_id,
        'obligation_pending_approval',
        new.id,
        new.regulatory_item_id,
        jsonb_build_object(
          'severity', new.severity::text,
          'compliance_status', new.compliance_status::text
        )
      from regwatch.organization_members m
      where m.organization_id = new.organization_id
        and m.role in ('owner', 'admin');
    end if;

    -- Verified → notify the assigned reviewer.
    if new.review_status = 'verified'
       and new.assigned_reviewer_user_id is not null
    then
      insert into regwatch.obligation_notification_queue
        (organization_id, recipient_user_id, kind, obligation_id,
         regulatory_item_id, payload)
      values (
        new.organization_id,
        new.assigned_reviewer_user_id,
        'obligation_signed_off',
        new.id,
        new.regulatory_item_id,
        jsonb_build_object('rationale', new.signoff_rationale)
      );
    end if;

    -- Kick-back from pending-approval back to in-review → notify reviewer.
    if old.review_status = 'pending-approval'
       and new.review_status = 'in-review'
       and new.assigned_reviewer_user_id is not null
    then
      insert into regwatch.obligation_notification_queue
        (organization_id, recipient_user_id, kind, obligation_id,
         regulatory_item_id, payload)
      values (
        new.organization_id,
        new.assigned_reviewer_user_id,
        'obligation_kicked_back',
        new.id,
        new.regulatory_item_id,
        coalesce(new.review_notes -> 'kickback_notes', '{}'::jsonb)
      );
    end if;
  end if;

  return new;
end;
$$;

drop trigger if exists compliance_obligations_notify_on_change on regwatch.compliance_obligations;
create trigger compliance_obligations_notify_on_change
  after update on regwatch.compliance_obligations
  for each row execute function regwatch.handle_obligation_change();

-- ===========================================================================
-- Trigger 3: on insert, notify the initial assignee (if any).
-- ===========================================================================
create or replace function regwatch.handle_obligation_insert_notify()
returns trigger
language plpgsql
security definer
set search_path = regwatch, public
as $$
begin
  if new.assigned_reviewer_user_id is not null then
    insert into regwatch.obligation_notification_queue
      (organization_id, recipient_user_id, kind, obligation_id,
       regulatory_item_id, payload)
    values (
      new.organization_id,
      new.assigned_reviewer_user_id,
      'obligation_assigned',
      new.id,
      new.regulatory_item_id,
      '{}'::jsonb
    );
  end if;
  return new;
end;
$$;

drop trigger if exists compliance_obligations_notify_on_insert on regwatch.compliance_obligations;
create trigger compliance_obligations_notify_on_insert
  after insert on regwatch.compliance_obligations
  for each row execute function regwatch.handle_obligation_insert_notify();

-- ---------------------------------------------------------------------------
-- Grants on the trigger functions
-- ---------------------------------------------------------------------------
grant execute on function regwatch.handle_regulation_change()           to service_role;
grant execute on function regwatch.handle_obligation_change()           to service_role;
grant execute on function regwatch.handle_obligation_insert_notify()    to service_role;


-- ===== MIGRATION: 20260619_regwatch_evidence_analysis.sql =====
-- ===========================================================================
-- RegWatch — AI Evidence Analysis (Phase A: schema + document analysis)
-- ---------------------------------------------------------------------------
-- Adds a junction table linking compliance_obligations to one-or-more uploaded
-- evidence files. Each file carries its own AI analysis lifecycle so a
-- reviewer can drop a PDF + 3 photos + a video and get per-file findings
-- back. The existing compliance_obligations.evidence_file_path column stays
-- as a denormalised "primary file" pointer for the existing summary cards.
--
-- Notifications: extends obligation_notification_kind with
-- evidence_analysis_completed + evidence_analysis_flagged_discrepancy.
-- ===========================================================================

-- ---------------------------------------------------------------------------
-- Enums
-- ---------------------------------------------------------------------------
create type regwatch.evidence_file_kind as enum (
  'document',  -- PDF / DOCX / TXT
  'image',     -- JPG / PNG / HEIC / WEBP
  'video'      -- MP4 / MOV (Enterprise-tier analysis only)
);

create type regwatch.evidence_analysis_status as enum (
  'pending',     -- queued for the analyse-evidence cron
  'processing',  -- cron picked it up, hasn't returned
  'completed',   -- success
  'failed',      -- error during analysis (see analysis_error)
  'skipped'      -- video uploaded by non-Enterprise org
);

create type regwatch.evidence_analysis_signal as enum (
  'looks-compliant',
  'concerns',
  'non-compliant',
  'inconclusive'
);

-- Severity for individual findings — separate from the obligation-level
-- severity enum because finding granularity is finer (we care about "low
-- severity" findings inside an otherwise high-severity obligation).
create type regwatch.evidence_finding_severity as enum (
  'info',
  'low',
  'medium',
  'high',
  'critical'
);

-- ---------------------------------------------------------------------------
-- obligation_evidence_files
-- ---------------------------------------------------------------------------
create table regwatch.obligation_evidence_files (
  id                  uuid primary key default gen_random_uuid(),
  organization_id     uuid not null references regwatch.organizations(id) on delete cascade,
  obligation_id       uuid not null references regwatch.compliance_obligations(id) on delete cascade,

  -- File metadata
  file_path           text not null,
  file_name           text not null,
  file_size           bigint,
  mime_type           text,
  file_kind           regwatch.evidence_file_kind not null,

  uploaded_by         uuid references auth.users(id) on delete set null,
  uploaded_at         timestamptz not null default now(),

  -- Analysis fields
  analysis_status     regwatch.evidence_analysis_status not null default 'pending',
  analysis_started_at timestamptz,
  analysis_completed_at timestamptz,
  analysis_model      text,              -- e.g. claude-sonnet-4-6 / claude-sonnet-4-6+whisper-1
  analysis_summary    text,              -- one-paragraph natural-language summary
  analysis_findings   jsonb not null default '[]'::jsonb,
  analysis_overall_signal regwatch.evidence_analysis_signal,
  analysis_confidence numeric(3,2) check (analysis_confidence between 0 and 1),
  analysis_token_usage jsonb not null default '{}'::jsonb,  -- {input, output, cache_read, cache_write}
  analysis_error      text,
  analysis_attempt_count int not null default 0,

  created_at          timestamptz not null default now(),
  updated_at          timestamptz not null default now()
);

create index obligation_evidence_obligation_idx
  on regwatch.obligation_evidence_files (obligation_id, uploaded_at desc);
create index obligation_evidence_org_idx
  on regwatch.obligation_evidence_files (organization_id);
create index obligation_evidence_pending_idx
  on regwatch.obligation_evidence_files (analysis_status, uploaded_at)
  where analysis_status in ('pending', 'processing');

create trigger obligation_evidence_files_set_updated_at
  before update on regwatch.obligation_evidence_files
  for each row execute function regwatch.set_updated_at();

-- ---------------------------------------------------------------------------
-- RLS
-- ---------------------------------------------------------------------------
alter table regwatch.obligation_evidence_files enable row level security;

drop policy if exists obligation_evidence_member_read on regwatch.obligation_evidence_files;
create policy obligation_evidence_member_read on regwatch.obligation_evidence_files
  for select to authenticated
  using (regwatch.is_org_member(organization_id));

-- Any org member can insert (server actions add the role check on top —
-- typically only the assigned reviewer or admins upload). Keeping RLS loose
-- so service-role + admin re-runs work.
drop policy if exists obligation_evidence_member_insert on regwatch.obligation_evidence_files;
create policy obligation_evidence_member_insert on regwatch.obligation_evidence_files
  for insert to authenticated
  with check (regwatch.is_org_member(organization_id));

drop policy if exists obligation_evidence_member_update on regwatch.obligation_evidence_files;
create policy obligation_evidence_member_update on regwatch.obligation_evidence_files
  for update to authenticated
  using (regwatch.is_org_member(organization_id))
  with check (regwatch.is_org_member(organization_id));

-- Only admins delete (preserves audit trail).
drop policy if exists obligation_evidence_admin_delete on regwatch.obligation_evidence_files;
create policy obligation_evidence_admin_delete on regwatch.obligation_evidence_files
  for delete to authenticated
  using (regwatch.is_org_admin(organization_id));

-- ---------------------------------------------------------------------------
-- Grants — explicit per the new-table-grant rule
-- ---------------------------------------------------------------------------
grant select, insert, update on regwatch.obligation_evidence_files to authenticated;
grant delete on regwatch.obligation_evidence_files to authenticated;
grant all on regwatch.obligation_evidence_files to service_role;

-- ---------------------------------------------------------------------------
-- Extend obligation_notification_kind enum
-- ---------------------------------------------------------------------------
alter type regwatch.obligation_notification_kind
  add value if not exists 'evidence_analysis_completed';
alter type regwatch.obligation_notification_kind
  add value if not exists 'evidence_analysis_flagged_discrepancy';


-- ===== MIGRATION: 20260620_regwatch_pending_invites_grants.sql =====
-- ===========================================================================
-- RegWatch — Service-role + authenticated grants on pending_invites
-- ---------------------------------------------------------------------------
-- Same root cause as 20260615 (the asset-management grant fix): the
-- pending_invites migration (20260608) never granted table-level access
-- explicitly. Server actions write to pending_invites via the service-role
-- client (createServiceClient) to bypass RLS, so they hit "permission
-- denied for table pending_invites" on every invite attempt.
--
-- Symptom this fixes: "permission denied for table pending_invites" when
-- an admin clicks "Add member" on /regwatch/settings/members for an
-- email that doesn't yet have an intelle.io account.
-- ===========================================================================

grant select, insert, update, delete on regwatch.pending_invites to authenticated;
grant all                              on regwatch.pending_invites to service_role;


-- ===== MIGRATION: 20260621_regwatch_evidence_video.sql =====
-- ===========================================================================
-- RegWatch — Evidence analysis Phase C (video) schema additions
-- ---------------------------------------------------------------------------
-- Adds:
--   - analysis_transcript text (Whisper output, segment-timestamps inline)
--   - analysis_keyframe_count int (how many frames we extracted and sent
