-- ===== MIGRATION: 20260701_regwatch_regulatory_sections.sql =====
-- ===========================================================================
-- Vantage — Regulatory sections hierarchy
-- ---------------------------------------------------------------------------
-- One row per node in a publisher's table-of-contents (Title → Chapter →
-- Subchapter → Part → Section for eCFR; analogous trees for EUR-Lex /
-- SASO / etc.). Leaf rows optionally link to the regulatory_items row when
-- the node IS the cited regulation; intermediate rows just describe the
-- structure so the browse UI can render an eCFR-style navigable tree.
--
-- Public corpus — read by everyone, written only by service-role.
-- ===========================================================================

create extension if not exists ltree;

create table regwatch.regulatory_sections (
  id                        uuid primary key default gen_random_uuid(),
  regulator_id              uuid not null references regwatch.regulators(id) on delete cascade,
  jurisdiction_code         text not null,
  parent_section_id         uuid references regwatch.regulatory_sections(id) on delete cascade,

  level                     int  not null check (level between 1 and 8),
  level_label               text not null,
  identifier                text not null,
  title                     text,

  -- When a node IS the cited regulation, the connector populates these so
  -- the browse leaf click jumps to the regulation detail page.
  citation                  text,
  regulatory_item_id        uuid references regwatch.regulatory_items(id) on delete set null,

  -- Denormalised for cheap UI rendering. `path` is the canonical full tree
  -- coordinate (e.g. 'us.cfr.title_1.chapter_i.subchapter_a.part_51'); it's
  -- the unique key so re-syncs are idempotent on identifier rename.
  path                      ltree not null,
  child_count               int not null default 0,
  has_updates_30d           boolean not null default false,
  last_changed_at           timestamptz,

  source_url                text,

  -- Soft-delete: when a node vanishes from the publisher's ToC we leave the
  -- row and null `last_seen_at` so any obligation/document references stay
  -- resolvable. Pruning is manual.
  last_seen_at              timestamptz not null default now(),

  created_at                timestamptz not null default now(),
  updated_at                timestamptz not null default now()
);

create unique index regulatory_sections_path_uq
  on regwatch.regulatory_sections (path);
create index regulatory_sections_parent_idx
  on regwatch.regulatory_sections (parent_section_id, identifier);
create index regulatory_sections_jurisdiction_idx
  on regwatch.regulatory_sections (jurisdiction_code);
create index regulatory_sections_regulator_idx
  on regwatch.regulatory_sections (regulator_id);
create index regulatory_sections_recent_idx
  on regwatch.regulatory_sections (regulator_id) where has_updates_30d;
create index regulatory_sections_item_idx
  on regwatch.regulatory_sections (regulatory_item_id) where regulatory_item_id is not null;
create index regulatory_sections_path_gist
  on regwatch.regulatory_sections using gist (path);

create trigger regulatory_sections_set_updated_at
  before update on regwatch.regulatory_sections
  for each row execute function regwatch.set_updated_at();

-- ---------------------------------------------------------------------------
-- RLS
-- ---------------------------------------------------------------------------
alter table regwatch.regulatory_sections enable row level security;

-- Browse is public — anon + authenticated can read.
drop policy if exists regulatory_sections_public_read on regwatch.regulatory_sections;
create policy regulatory_sections_public_read on regwatch.regulatory_sections
  for select to anon, authenticated
  using (true);

-- Writes only via service-role (cron). No auth-user inserts / updates.

-- ---------------------------------------------------------------------------
-- Grants
-- ---------------------------------------------------------------------------
grant select on regwatch.regulatory_sections to anon, authenticated;
grant all    on regwatch.regulatory_sections to service_role;

-- ---------------------------------------------------------------------------
-- Helper: refresh has_updates_30d + last_changed_at from current items.
-- Walks bottom-up so each non-leaf node summarises its descendants.
-- Called by the regwatch-hierarchy cron at the end of every sync.
-- ---------------------------------------------------------------------------
create or replace function regwatch.refresh_regulatory_section_recency()
returns void
language plpgsql
security definer
set search_path = regwatch, public
as $$
begin
  -- Leaves: pull from the linked regulatory_item.
  update regwatch.regulatory_sections rs
     set has_updates_30d = (ri.last_changed_at >= now() - interval '30 days'),
         last_changed_at = ri.last_changed_at
    from regwatch.regulatory_items ri
   where rs.regulatory_item_id = ri.id;

  -- Internal nodes: any descendant has_updates_30d=true → roll up.
  -- Single pass via path-prefix join (cheap with the GiST index).
  update regwatch.regulatory_sections parent
     set has_updates_30d = exists (
       select 1
         from regwatch.regulatory_sections child
        where child.path <@ parent.path
          and child.id <> parent.id
          and child.has_updates_30d
     ),
     last_changed_at = (
       select max(child.last_changed_at)
         from regwatch.regulatory_sections child
        where child.path <@ parent.path
          and child.id <> parent.id
     )
   where parent.regulatory_item_id is null;
end;
$$;

grant execute on function regwatch.refresh_regulatory_section_recency() to service_role;


-- ===== MIGRATION: 20260702_regwatch_original_document_capture.sql =====
-- ===========================================================================
-- Vantage — Original document capture (cached source PDF/HTML)
-- ---------------------------------------------------------------------------
-- Adds the storage hooks for the Original tab on the regulation reader.
-- The Original tab shows the canonical source document (PDF or HTML)
-- cached in Supabase Storage and rendered via the existing react-pdf
-- viewer used for internal-doc previews.
--
-- Capture is lazy: triggered on first viewer hit, stamped here. The
-- source_mime column also gets populated by connectors that sniff
-- Content-Type at crawl time (SASO's mixed PDF/HTML index, mostly).
-- ===========================================================================

-- Add capture columns to regulatory_items
alter table regwatch.regulatory_items
  add column if not exists original_storage_path  text,
  add column if not exists original_mime          text,
  add column if not exists original_size_bytes    bigint,
  add column if not exists original_captured_at   timestamptz,
  add column if not exists original_capture_error text,
  -- source_mime: connector-sniffed Content-Type, separate from the
  -- captured copy's mime so we can distinguish "what the publisher
  -- says it is" from "what we successfully cached".
  add column if not exists source_mime            text;

create index if not exists regulatory_items_no_original_idx
  on regwatch.regulatory_items (id)
  where original_storage_path is null and source_url is not null;

-- ---------------------------------------------------------------------------
-- Storage bucket: regwatch-public
-- ---------------------------------------------------------------------------
-- Public read for compliance evidence — cached source documents are
-- redistributions of explicitly-public government records. Signed URLs
-- still get used by the action for cache busting, but anonymous read
-- is fine because the underlying source is itself public.
insert into storage.buckets (id, name, public, file_size_limit, allowed_mime_types)
values (
  'regwatch-public',
  'regwatch-public',
  true,
  52428800, -- 50 MB ceiling — biggest regulator PDFs we've seen are ~30 MB
  array['application/pdf', 'text/html']
)
on conflict (id) do update
  set public = excluded.public,
      file_size_limit = excluded.file_size_limit,
      allowed_mime_types = excluded.allowed_mime_types;

-- Policy: anyone can read the bucket (it's public regulator docs)
drop policy if exists regwatch_public_read on storage.objects;
create policy regwatch_public_read on storage.objects
  for select to anon, authenticated
  using (bucket_id = 'regwatch-public');

-- Policy: only service-role can write (the capture action runs server-side)
-- Nothing further needed — service_role bypasses RLS by default.

-- ---------------------------------------------------------------------------
-- Per-publisher kill-switch
-- ---------------------------------------------------------------------------
-- For the rare publisher that objects to redistribution we flip this
-- column and the action falls back to a "open at source" button instead
-- of capturing. Defaults to allowed; flip per-regulator on objection.
alter table regwatch.regulators
  add column if not exists disallow_original_capture boolean not null default false;


-- ===== MIGRATION: 20260703_regwatch_saso_regulator.sql =====
-- ===========================================================================
-- Vantage — SASO regulator seed
-- ---------------------------------------------------------------------------
-- Adds the Saudi Standards, Metrology and Quality Organization as a real
-- publisher row so the SASO connector (PR-E) has a regulator_id to write
-- against and the Discover landing's Saudi card lights up.
-- ===========================================================================

insert into regwatch.regulators
  (slug, name, short_name, jurisdiction_code, jurisdiction_name, region, regulator_type, canonical_url, description, topic_domains)
values
  ('sa-saso',
   'Saudi Standards, Metrology and Quality Organization',
   'SASO',
   'SA',
   'Saudi Arabia',
   'mea',
   'standards-body',
   'https://www.saso.gov.sa',
   'National standards body for the Kingdom of Saudi Arabia — issues technical regulations, mandatory and voluntary standards, GSO-aligned conformity requirements across food, chemicals, energy, electronics, vehicles, toys, cosmetics, and construction materials.',
   '{standards,gulf,gcc-alignment,energy,chemicals,worker-safety}'::text[])
on conflict (slug) do update
  set name = excluded.name,
      short_name = excluded.short_name,
      jurisdiction_name = excluded.jurisdiction_name,
      region = excluded.region,
      regulator_type = excluded.regulator_type,
      canonical_url = excluded.canonical_url,
      description = excluded.description,
      topic_domains = excluded.topic_domains;


-- ===== MIGRATION: 20260704_regwatch_saved_searches.sql =====
-- ===========================================================================
-- Vantage — Saved searches
-- ---------------------------------------------------------------------------
-- Per-user catalogue of saved corpus queries. Surfaced on /regwatch/saved
-- (replaces the coming-soon shell). One row per saved query; label is
-- optional ("How does CBAM apply to imports?" → user can rename).
-- ===========================================================================

create table regwatch.saved_searches (
  id                  uuid primary key default gen_random_uuid(),
  user_id             uuid not null references auth.users(id) on delete cascade,
  organization_id     uuid references regwatch.organizations(id) on delete cascade,

  query               text not null,
  label               text,
  -- Future-proof: filters jsonb so faceted searches (jurisdiction, topic
  -- etc.) can attach without a schema bump.
  filters             jsonb not null default '{}'::jsonb,
  -- Snapshot of how many corpus rows matched at save time. Useful for the
  -- list view to show stale-result badges.
  result_count_at_save int,
  last_run_at         timestamptz,

  created_at          timestamptz not null default now(),
  updated_at          timestamptz not null default now()
);

-- One save per (user, normalised query) — re-saving updates the timestamp
-- rather than creating a duplicate row.
create unique index saved_searches_user_query_uq
  on regwatch.saved_searches (user_id, lower(query));
create index saved_searches_user_idx
  on regwatch.saved_searches (user_id, created_at desc);

create trigger saved_searches_set_updated_at
  before update on regwatch.saved_searches
  for each row execute function regwatch.set_updated_at();

alter table regwatch.saved_searches enable row level security;

drop policy if exists saved_searches_owner_read on regwatch.saved_searches;
create policy saved_searches_owner_read on regwatch.saved_searches
  for select to authenticated
  using (user_id = auth.uid());

drop policy if exists saved_searches_owner_insert on regwatch.saved_searches;
create policy saved_searches_owner_insert on regwatch.saved_searches
  for insert to authenticated
  with check (user_id = auth.uid());

drop policy if exists saved_searches_owner_update on regwatch.saved_searches;
create policy saved_searches_owner_update on regwatch.saved_searches
  for update to authenticated
  using (user_id = auth.uid())
  with check (user_id = auth.uid());

drop policy if exists saved_searches_owner_delete on regwatch.saved_searches;
create policy saved_searches_owner_delete on regwatch.saved_searches
  for delete to authenticated
  using (user_id = auth.uid());

grant select, insert, update, delete on regwatch.saved_searches to authenticated;
grant all on regwatch.saved_searches to service_role;


-- ===== MIGRATION: 20260705_regwatch_saso_seed_items.sql =====
-- ===========================================================================
-- Vantage — SASO regulation seed items
-- ---------------------------------------------------------------------------
-- Hand-curated set of 25 real SASO technical regulations covering the
-- vertical we care about most (energy, vehicles, food, electronics, toys,
-- cosmetics, fuels). Gives the Saudi card visible content before the live
-- scraper completes its first successful run.
--
-- The live SASO connector still runs nightly and upserts on
-- (regulator_id, citation) — if a hand-seeded item matches a citation
-- the scraper later finds, the row stays the same; the scraper just
-- refreshes timestamps.
-- ===========================================================================

-- Insert SASO regulator if not already present (the prior 20260703
-- migration handles this; redoing it idempotently in case those run
-- out of order in a fresh DB).
insert into regwatch.regulators
  (slug, name, short_name, jurisdiction_code, jurisdiction_name, region, regulator_type, canonical_url, description, topic_domains)
values
  ('sa-saso',
   'Saudi Standards, Metrology and Quality Organization',
   'SASO',
   'SA',
   'Saudi Arabia',
   'mea',
   'standards-body',
   'https://www.saso.gov.sa',
   'National standards body for the Kingdom of Saudi Arabia — issues technical regulations, mandatory and voluntary standards, GSO-aligned conformity requirements across food, chemicals, energy, electronics, vehicles, toys, cosmetics, and construction materials.',
   '{standards,gulf,gcc-alignment,energy,chemicals,worker-safety}'::text[])
on conflict (slug) do nothing;

-- Resolve regulator_id for the SASO inserts below.
with saso as (
  select id from regwatch.regulators where slug = 'sa-saso'
)
insert into regwatch.regulatory_items
  (regulator_id, citation, slug, title, instrument_type, status,
   effective_date, published_at, last_changed_at, source_url,
   summary, jurisdiction_code, topics, enrichment_status)
