  saso.id,
  v.citation,
  v.slug,
  v.title,
  v.instrument_type::regwatch.instrument_type,
  v.status::regwatch.item_status,
  v.effective_date::date,
  v.published_at::timestamptz,
  v.last_changed_at::timestamptz,
  v.source_url,
  v.summary,
  'SA',
  v.topics::text[],
  'pending'
from saso, (values
  -- Energy efficiency
  ('SASO 2870', 'saso-2870',
   'Energy labelling and minimum efficiency for room air conditioners',
   'standard', 'in-force', '2018-01-01', '2017-09-15', '2024-03-10',
   'https://www.saso.gov.sa/en/Laws-And-Regulations/Technical_regulations/Pages/SASO-2870.aspx',
   'Mandatory energy efficiency labelling and minimum energy performance standards for split, window, and packaged air conditioners up to 65 kW cooling capacity sold in Saudi Arabia.',
