   'MEPS + label for household refrigerator-freezers, freezers, and wine coolers ≤1500L. Includes star-rating display and bilingual Arabic-English label format.',
   '{standards,energy,gcc-alignment}'),
  ('SASO 2884', 'saso-2884',
   'Energy efficiency standards for clothes washing machines',
   'standard', 'in-force', '2019-06-01', '2019-02-15', '2024-05-20',
   'https://www.saso.gov.sa/en/Laws-And-Regulations/Technical_regulations/Pages/SASO-2884.aspx',
   'Mandatory energy efficiency labelling for top-loading and front-loading washing machines up to 12 kg load capacity.',
   '{standards,energy}'),
  ('SASO 2902', 'saso-2902',
   'Safety requirements for toys — Mechanical and physical properties',
   'standard', 'in-force', '2020-01-01', '2019-08-10', '2024-01-12',
   'https://www.saso.gov.sa/en/Laws-And-Regulations/Technical_regulations/Pages/SASO-2902.aspx',
   'Mechanical and physical safety requirements for toys imported into or manufactured in the Kingdom; covers small parts, sharp edges, projectiles, magnets, sound levels. Aligned with EN 71-1.',
   '{standards,worker-safety}'),
  -- Vehicles + fuels
  ('SASO 2530', 'saso-2530',
   'Vehicle tyres — Specifications and test methods',
   'standard', 'in-force', '2018-07-01', '2017-12-04', '2023-08-30',
   'https://www.saso.gov.sa/en/Laws-And-Regulations/Technical_regulations/Pages/SASO-2530.aspx',
   'Performance, dimensional and marking requirements for new passenger-car, light-truck, and heavy-duty tyres sold in Saudi Arabia. Includes desert-temperature endurance tests.',
   '{standards,gcc-alignment}'),
  ('SASO 2078', 'saso-2078',
   'Petroleum products — Unleaded gasoline for motor vehicles',
   'standard', 'in-force', '2017-09-01', '2017-04-15', '2024-09-05',
