-- ===== MIGRATION: 20260710_regwatch_regulation_translation.sql =====
-- ===========================================================================
-- Vantage — Regulation translation (Arabic / French / etc. → English)
-- ---------------------------------------------------------------------------
-- For non-English source regulations (e.g. SASO Technical Regulations
-- which are Arabic-only), the Regulation reader will offer an English
-- translation tab alongside the Articles + Original tabs. The tab calls
-- a server action that:
--   1. Extracts text from the cached Original PDF via `unpdf`
--   2. Translates via Claude (technical / regulatory prompt)
--   3. Caches the result in these columns so subsequent views are fast
--
-- Source language defaults to 'en' for everything already in the
-- corpus (US Fed Register, EUR-Lex English versions, GOV.UK, etc.).
-- The SASO seed (20260709) flips its rows to 'ar' after this migration.
-- ===========================================================================

alter table regwatch.regulatory_items
  add column if not exists source_language text not null default 'en',
  add column if not exists translated_text text,
  add column if not exists translated_into text,
  add column if not exists translated_at timestamptz,
  add column if not exists translation_model text,
  add column if not exists translation_source_chars int;

create index if not exists regulatory_items_source_lang_idx
  on regwatch.regulatory_items (source_language)
  where source_language <> 'en';

-- Mark all existing SASO rows as Arabic source.
update regwatch.regulatory_items
   set source_language = 'ar'
 where regulator_id = (select id from regwatch.regulators where slug = 'sa-saso')
   and source_language = 'en';


-- ===== MIGRATION: 20260711_regwatch_eu_source_urls_to_eli.sql =====
-- ===========================================================================
-- Vantage — Convert EU regulation source URLs to the stable ELI format
-- ---------------------------------------------------------------------------
-- The 20260605 seed wrote EUR-Lex URLs in the
-- /legal-content/EN/TXT/?uri=CELEX:32024R1787
-- form. That format works but routes through an EUR-Lex redirect
-- layer that occasionally returns a "Document not found" page (the
-- 404 the user observed). The W3C ELI (European Legislation
-- Identifier) format goes straight to the document and is the
-- EUR-Lex-recommended stable URL.
--
-- Mapping:
--   CELEX 3YYYYR<num>  →  /eli/reg/YYYY/<num>
--   CELEX 3YYYYL<num>  →  /eli/dir/YYYY/<num>
--   CELEX 3YYYYD<num>  →  /eli/dec/YYYY/<num>
-- Leading zeros on <num> are stripped (ELI uses unpadded numbers).
-- ===========================================================================

-- Regulations
update regwatch.regulatory_items
   set source_url = regexp_replace(
     source_url,
     '^https?://eur-lex\.europa\.eu/legal-content/[A-Z]+/[A-Z]+/\?uri=CELEX(?::|%3A)3(\d{4})R0*(\d+).*$',
     'https://eur-lex.europa.eu/eli/reg/\1/\2'
   )
 where source_url ~ 'eur-lex\.europa\.eu/legal-content/[A-Z]+/[A-Z]+/\?uri=CELEX(?::|%3A)3\d{4}R\d+';

-- Directives
update regwatch.regulatory_items
   set source_url = regexp_replace(
     source_url,
     '^https?://eur-lex\.europa\.eu/legal-content/[A-Z]+/[A-Z]+/\?uri=CELEX(?::|%3A)3(\d{4})L0*(\d+).*$',
     'https://eur-lex.europa.eu/eli/dir/\1/\2'
   )
 where source_url ~ 'eur-lex\.europa\.eu/legal-content/[A-Z]+/[A-Z]+/\?uri=CELEX(?::|%3A)3\d{4}L\d+';

-- Decisions
update regwatch.regulatory_items
   set source_url = regexp_replace(
     source_url,
     '^https?://eur-lex\.europa\.eu/legal-content/[A-Z]+/[A-Z]+/\?uri=CELEX(?::|%3A)3(\d{4})D0*(\d+).*$',
     'https://eur-lex.europa.eu/eli/dec/\1/\2'
   )
 where source_url ~ 'eur-lex\.europa\.eu/legal-content/[A-Z]+/[A-Z]+/\?uri=CELEX(?::|%3A)3\d{4}D\d+';

-- Invalidate any cached original-document captures for these rows so
-- the Original tab refetches against the new (working) URL. Wrapped
-- in a DO block so it's a no-op when 20260702's capture columns
-- haven't been applied yet.
do $$
begin
  if exists (
    select 1 from information_schema.columns
     where table_schema = 'regwatch'
       and table_name = 'regulatory_items'
       and column_name = 'original_storage_path'
  ) then
    execute $clear$
      update regwatch.regulatory_items
         set original_storage_path = null,
             original_mime = null,
             original_size_bytes = null,
             original_captured_at = null,
             original_capture_error = null
       where source_url like 'https://eur-lex.europa.eu/eli/%'
    $clear$;
  end if;
end $$;


-- ===== MIGRATION: 20260712_regwatch_eu_eli_v2_robust.sql =====
-- ===========================================================================
-- Vantage — Robust EU CELEX → ELI URL conversion (replaces / supplements 20260711)
-- ---------------------------------------------------------------------------
-- 20260711's regex required the URL to start with the exact form
-- `legal-content/<LANG>/<DOMAIN>/` — if the URL had any trailing
-- parameters or used a slightly different shape it wouldn't match.
-- This version uses substring() to extract just the CELEX year +
-- number, then rebuilds the URL from scratch. Robust to:
--   - any URL prefix (just needs CELEX somewhere)
--   - colon / %3A / space variants between CELEX and the number
--   - trailing query params, fragments, etc.
-- Cast through ::int drops leading zeros so /eli/reg/2024/1787 not
-- /eli/reg/2024/01787.
-- ===========================================================================

-- Regulations (R)
update regwatch.regulatory_items
   set source_url = 'https://eur-lex.europa.eu/eli/reg/'
     || substring(source_url from 'CELEX[^0-9]*3(\d{4})R')
     || '/'
     || (substring(source_url from 'CELEX[^0-9]*3\d{4}R0*(\d+)')::int)::text
 where source_url ~* 'eur-lex'
   and source_url ~ 'CELEX[^0-9]*3\d{4}R\d+'
   and source_url not like 'https://eur-lex.europa.eu/eli/%';

-- Directives (L)
update regwatch.regulatory_items
   set source_url = 'https://eur-lex.europa.eu/eli/dir/'
     || substring(source_url from 'CELEX[^0-9]*3(\d{4})L')
     || '/'
     || (substring(source_url from 'CELEX[^0-9]*3\d{4}L0*(\d+)')::int)::text
 where source_url ~* 'eur-lex'
   and source_url ~ 'CELEX[^0-9]*3\d{4}L\d+'
   and source_url not like 'https://eur-lex.europa.eu/eli/%';

-- Decisions (D)
update regwatch.regulatory_items
   set source_url = 'https://eur-lex.europa.eu/eli/dec/'
     || substring(source_url from 'CELEX[^0-9]*3(\d{4})D')
     || '/'
     || (substring(source_url from 'CELEX[^0-9]*3\d{4}D0*(\d+)')::int)::text
 where source_url ~* 'eur-lex'
   and source_url ~ 'CELEX[^0-9]*3\d{4}D\d+'
   and source_url not like 'https://eur-lex.europa.eu/eli/%';

-- Invalidate any cached original-document captures for the rewritten
-- rows so the Original tab refetches the working URL. Guarded by an
-- information_schema check so it's a no-op when 20260702's capture
-- columns aren't installed yet.
do $$
begin
  if exists (
    select 1 from information_schema.columns
     where table_schema = 'regwatch'
       and table_name = 'regulatory_items'
       and column_name = 'original_storage_path'
  ) then
    execute $clear$
      update regwatch.regulatory_items
         set original_storage_path = null,
             original_mime = null,
             original_size_bytes = null,
             original_captured_at = null,
             original_capture_error = null
       where source_url like 'https://eur-lex.europa.eu/eli/%'
    $clear$;
  end if;
end $$;

-- Sanity print: how many EU rows still have legacy CELEX URLs?
do $$
declare
  remaining int;
begin
  select count(*) into remaining
    from regwatch.regulatory_items
   where jurisdiction_code = 'EU'
     and source_url ~ 'CELEX[^0-9]*3\d{4}[A-Z]\d+'
     and source_url not like 'https://eur-lex.europa.eu/eli/%';
  raise notice 'EU rows still on legacy CELEX URL form: %', remaining;
end $$;


-- ===== MIGRATION: 20260713_regwatch_saso_predicted_pdf_urls.sql =====
-- ===========================================================================
-- Vantage — Predict SASO Technical Regulation PDF URLs from titles
-- ---------------------------------------------------------------------------
-- The user shared one real PDF URL:
--   https://www.saso.gov.sa/en/Laws-And-Regulations/Technical_regulations/Documents/Technical-Regulation-Autonomous-Vehicles.pdf
--
-- Pattern:
--   Base: https://www.saso.gov.sa/en/Laws-And-Regulations/Technical_regulations/Documents/
--   File: Technical-Regulation-<Title-with-prefix-stripped-and-spaces-hyphenated>.pdf
--
-- This migration updates every seeded SASO row's source_url to the
-- predicted PDF URL based on its title. Strips "Technical Regulation
-- for " prefix, normalises whitespace + em-dashes + ampersands.
--
-- Predicted URLs that 404 will need manual correction once we have
-- the user's authoritative PDF list (the SASO scraper can't introspect
-- the live HTML, so deterministic title→URL mapping is the best we
-- can do).
-- ===========================================================================

update regwatch.regulatory_items
   set source_url = 'https://www.saso.gov.sa/en/Laws-And-Regulations/Technical_regulations/Documents/Technical-Regulation-'
     || regexp_replace(
       regexp_replace(
         regexp_replace(
           -- Strip "Technical Regulation for " or "Technical Regulation of " prefix
           regexp_replace(title, '^Technical Regulation (?:for|of)\s+', '', 'i'),
           -- Normalise em-dash / en-dash to a plain hyphen with surrounding spaces collapsed
           '\s*[—–]\s*', ' ', 'g'
         ),
         -- Ampersand → 'and'
         '\s*&\s*', ' and ', 'g'
       ),
       -- Whitespace runs → single hyphen
       '\s+', '-', 'g'
     )
     || '.pdf',
       source_mime = 'application/pdf'
 where regulator_id = (select id from regwatch.regulators where slug = 'sa-saso')
   -- Only touch rows that still have the placeholder index URL
   and source_url like '%Technical_regulations/pages/default.aspx';

-- Invalidate any cached original-document captures for these rows so
-- the Original tab refetches against the new URLs. Guarded for
-- DBs that don't have 20260702 applied yet.
do $$
begin
  if exists (
    select 1 from information_schema.columns
     where table_schema = 'regwatch'
       and table_name = 'regulatory_items'
       and column_name = 'original_storage_path'
  ) then
    execute $clear$
      update regwatch.regulatory_items
         set original_storage_path = null,
             original_mime = null,
             original_size_bytes = null,
             original_captured_at = null,
             original_capture_error = null,
             translated_text = null,
             translated_at = null,
             translation_model = null
       where regulator_id = (select id from regwatch.regulators where slug = 'sa-saso')
    $clear$;
  end if;
end $$;

-- Sanity output: how many SASO rows got updated, what the URLs look like
do $$
declare
  rec record;
begin
  for rec in
    select citation, source_url
      from regwatch.regulatory_items
     where regulator_id = (select id from regwatch.regulators where slug = 'sa-saso')
     order by citation
     limit 5
  loop
    raise notice 'SASO % → %', rec.citation, rec.source_url;
  end loop;
end $$;


-- ===== MIGRATION: 20260714_regwatch_eu_human_citations_and_slugs.sql =====
-- ===========================================================================
-- Vantage — Human-readable EU citations + clean slugs (drop CELEX from URLs)
-- ---------------------------------------------------------------------------
-- EU rows crawled by the eur-lex connector ended up with:
--   citation = "CELEX:32026D0723"   (machine-readable but unfriendly)
--   slug     = "celex-32026d0723"   (URL has 'celex' in it — user dislike)
--
-- This migration rewrites both into the seed convention so:
--   citation = "Decision (EU) 2026/723"
--   slug     = "eu-dec-2026-723"
--
-- CELEX type letter → slug prefix:
--   R Regulation     → eu-reg-YYYY-N
--   L Directive      → eu-dir-YYYY-N
--   D Decision       → eu-dec-YYYY-N
--   H Recommendation → eu-rec-YYYY-N
--   C Communication  → eu-com-YYYY-N
--   X Notice         → eu-notice-YYYY-N
-- Number digits are unpadded via ::int cast so /eli/reg/2024/1787, not 01787.
--
-- After this:
--   - Existing seed rows with citation "Regulation (EU) 2024/1787" + slug
--     "eu-2024-1787" stay the same; their slugs ALSO migrate to the
--     "eu-reg-2024-1787" form so the URL pattern is consistent.
--   - Connector-crawled rows with "CELEX:..." citations get the human form.
--
-- 301 redirects from the old slug paths aren't needed because the only
-- external-link surface (the corpus search) regenerates href from the
-- current slug on every render.
-- ===========================================================================

-- 1. CELEX-citation rows → human citation + new slug
update regwatch.regulatory_items
   set
     citation = case substring(citation from 'CELEX:3\d{4}([A-Z])')
                  when 'R' then 'Regulation (EU) '
                  when 'L' then 'Directive (EU) '
                  when 'D' then 'Decision (EU) '
                  when 'H' then 'Recommendation (EU) '
                  when 'C' then 'Communication (EU) '
                  when 'X' then 'Notice (EU) '
                  else 'EU Act '
                end
                || substring(citation from 'CELEX:3(\d{4})[A-Z]')
                || '/'
                || (substring(citation from 'CELEX:3\d{4}[A-Z]0*(\d+)')::int)::text,
     slug = 'eu-'
            || case substring(citation from 'CELEX:3\d{4}([A-Z])')
                 when 'R' then 'reg'
                 when 'L' then 'dir'
                 when 'D' then 'dec'
                 when 'H' then 'rec'
                 when 'C' then 'com'
                 when 'X' then 'notice'
                 else 'act'
               end
            || '-'
            || substring(citation from 'CELEX:3(\d{4})[A-Z]')
            || '-'
            || (substring(citation from 'CELEX:3\d{4}[A-Z]0*(\d+)')::int)::text
 where citation ~ '^CELEX:3\d{4}[A-Z]\d+';

-- 2. Seed-style rows ("Regulation (EU) YYYY/N" with old "eu-YYYY-N" slug)
--    get the new "eu-{type}-YYYY-N" slug for URL consistency.
update regwatch.regulatory_items
   set slug = 'eu-'
              || case substring(citation from '^(\w+)\s+\(EU\)')
                   when 'Regulation' then 'reg'
                   when 'Directive' then 'dir'
                   when 'Decision' then 'dec'
                   when 'Recommendation' then 'rec'
                   when 'Communication' then 'com'
                   when 'Notice' then 'notice'
                   else 'act'
                 end
              || '-'
              || substring(citation from '\(EU\)\s+(\d{4})/')
              || '-'
              || (substring(citation from '\(EU\)\s+\d{4}/0*(\d+)')::int)::text
 where jurisdiction_code = 'EU'
   and citation ~ '^(Regulation|Directive|Decision|Recommendation|Communication|Notice)\s+\(EU\)\s+\d{4}/\d+'
   and slug !~ '^eu-(reg|dir|dec|rec|com|notice|act)-\d{4}-\d+';

-- 3. Sanity print
do $$
declare
  rec record;
begin
  raise notice '--- EU citation / slug sample after rewrite ---';
  for rec in
    select citation, slug, source_url
      from regwatch.regulatory_items
     where jurisdiction_code = 'EU'
     order by last_changed_at desc
     limit 6
  loop
    raise notice 'citation=% slug=%  source=%', rec.citation, rec.slug, rec.source_url;
  end loop;
end $$;


-- ===== MIGRATION: 20260715_regwatch_dedupe_cross_publisher_eu_rows.sql =====
-- ===========================================================================
-- Vantage — Dedupe EU regulations duplicated across publisher variants
-- ---------------------------------------------------------------------------
-- The eur-lex connector ships as multiple topic-filtered variants
-- (eurlex-dg-clima, eurlex-dg-ener). The same CELEX regulation often
-- surfaces under both topic filters and gets inserted twice — once per
-- publisher. The (regulator_id, citation) unique constraint allowed it
-- because the regulator_ids differ.
--
-- After 20260714 rewrote slugs into the eu-{type}-YYYY-N form, those
-- twin rows share the same slug, so the detail page's .maybeSingle()
-- query errors with "Cannot coerce the result to a single JSON object"
-- and the user sees a 404.
--
-- This migration:
--   1. Identifies (jurisdiction_code, slug) pairs that have >1 row.
--   2. Keeps the row with the most recent last_changed_at (or the
--      lowest id if tied — fully deterministic).
--   3. Deletes the other(s).
--
-- Run-once; idempotent because the dedupe is a no-op when no
-- duplicates remain.
-- ===========================================================================

with ranked as (
  select id,
         row_number() over (
           partition by jurisdiction_code, slug
           order by last_changed_at desc, id asc
         ) as rn
    from regwatch.regulatory_items
)
delete from regwatch.regulatory_items ri
 using ranked
 where ri.id = ranked.id
   and ranked.rn > 1;

-- Sanity print: any (jurisdiction_code, slug) pairs still duplicated?
do $$
declare
  remaining int;
begin
  select count(*) into remaining
    from (
      select jurisdiction_code, slug, count(*) as n
        from regwatch.regulatory_items
       group by jurisdiction_code, slug
      having count(*) > 1
    ) dupes;
  raise notice 'Remaining (jurisdiction, slug) duplicate groups: %', remaining;
end $$;


