-- ===== MIGRATION: 20260717_regwatch_saso_force_arabic_source.sql =====
-- ===========================================================================
-- Vantage — Mark every SASO regulation as Arabic-source
-- ---------------------------------------------------------------------------
-- 20260716 set source_language from the URL path (/en/ → en, /ar/ → ar)
-- assuming SASO uses the URL path to signal document language. That
-- assumption is wrong: SASO publishes PDFs in Arabic regardless of
-- which language page links to them. The user reported that the
-- Autonomous Vehicles regulation — seeded from a /en/ URL — opens as
-- an Arabic PDF, so the English-translation tab never appeared.
--
-- Fix: override every SASO row to source_language='ar'. The English
-- tab now shows on all SASO regulations and Claude translates each on
-- first viewer hit. If a specific SASO PDF turns out to already be
-- English in content, the translation step would still run but the
-- output would just be near-identical to the input — harmless.
-- ===========================================================================

update regwatch.regulatory_items
   set source_language = 'ar'
 where regulator_id = (select id from regwatch.regulators where slug = 'sa-saso')
   and source_language <> 'ar';

-- Invalidate any cached translations so they re-run with the new
-- source_language assumption. Guarded for DBs that don't have the
-- translation columns yet.
do $$
begin
  if exists (
    select 1 from information_schema.columns
     where table_schema = 'regwatch'
       and table_name = 'regulatory_items'
       and column_name = 'translated_text'
  ) then
    execute $clear$
      update regwatch.regulatory_items
         set translated_text = null,
             translated_at = null,
             translated_into = null,
             translation_model = null
       where regulator_id = (select id from regwatch.regulators where slug = 'sa-saso')
    $clear$;
  end if;
end $$;

do $$
declare
  n int;
begin
  select count(*) into n
    from regwatch.regulatory_items
   where regulator_id = (select id from regwatch.regulators where slug = 'sa-saso')
     and source_language = 'ar';
  raise notice 'SASO rows now marked Arabic-source: %', n;
end $$;


-- ===== MIGRATION: 20260718_regwatch_translation_background_status.sql =====
-- ===========================================================================
-- Vantage — Translation background-job status tracking
-- ---------------------------------------------------------------------------
-- The synchronous server-action translation pattern was hitting Vercel
-- function timeouts and leaving the UI stuck on "Translating…" with no
-- progress. New pattern: an API route kicks off the work via next/after
-- so it survives client disconnect, and the client polls a status endpoint
-- every 2s. These columns track that lifecycle.
--
--   translation_status:
--     null / 'not_started' — never attempted
--     'in_progress'        — work is running server-side
--     'completed'          — translated_text is populated and fresh
--     'failed'             — last attempt errored; translation_error has details
--
--   translation_started_at: stamps when 'in_progress' began so the route
--     can detect stale-in-progress (>5 min) and retry.
--   translation_error: latest failure message for UI surfacing.
-- ===========================================================================

alter table regwatch.regulatory_items
  add column if not exists translation_status text,
  add column if not exists translation_started_at timestamptz,
  add column if not exists translation_error text;

-- Backfill: any row that already has translated_text counts as completed.
update regwatch.regulatory_items
   set translation_status = 'completed'
 where translated_text is not null
   and translation_status is null;


